-- -----------------------------------------------------------------------------
-- 020_audit\usp_get_sku_changes.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE audit.usp_get_sku_changes
(
    @sku_code  NVARCHAR(50) = NULL,
    @from_date DATE         = NULL,
    @to_date   DATE         = NULL,
    @top       INT          = 200
)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT TOP (@top)
        trace_id,
        occurred_at,
        username,
        action_type,
        sku_code,
        desc_before,     ean_before,       uom_before,       weight_before,
        hu_qty_before,   batch_req_before,  full_hu_req_before,
        hazardous_before, active_before,   storage_before,   section_before,   owner_before,
        desc_after,      ean_after,        uom_after,        weight_after,
        hu_qty_after,    batch_req_after,   full_hu_req_after,
        hazardous_after,  active_after,    storage_after,    section_after,    owner_after
    FROM audit.v_sku_changes
    WHERE (@sku_code  IS NULL OR sku_code     = @sku_code)
      AND (@from_date IS NULL OR occurred_at >= @from_date)
      AND (@to_date   IS NULL OR occurred_at <  DATEADD(DAY, 1, @to_date))
    ORDER BY occurred_at DESC;
END;
GO


-- -----------------------------------------------------------------------------
-- 020_audit\usp_log_event.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE audit.usp_log_event
(
    @correlation_id UNIQUEIDENTIFIER = NULL,
    @user_id        INT = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @event_name     NVARCHAR(200),
    @result_code    NVARCHAR(50),
    @success        BIT,
    @payload_json   NVARCHAR(MAX) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;

    --------------------------------------------------------
    -- Normalize input (trim only, no magic)
    --------------------------------------------------------

    SET @event_name  = LTRIM(RTRIM(@event_name));
    SET @result_code = LTRIM(RTRIM(@result_code));

    --------------------------------------------------------
    -- Validation
    --------------------------------------------------------

    IF @event_name IS NULL OR @event_name = ''
        THROW 50001, 'audit.usp_log_event: @event_name is required.', 1;

    IF @result_code IS NULL OR @result_code = ''
        THROW 50002, 'audit.usp_log_event: @result_code is required.', 1;

    IF @payload_json IS NOT NULL AND ISJSON(@payload_json) <> 1
        THROW 50003, 'audit.usp_log_event: @payload_json must be valid JSON.', 1;

    --------------------------------------------------------
    -- Insert (constraints enforce correctness)
    --------------------------------------------------------

    INSERT INTO audit.audit_events
    (
        occurred_at,
        correlation_id,
        user_id,
        session_id,
        event_name,
        result_code,
        success,
        payload_json
    )
    VALUES
    (
        SYSUTCDATETIME(),
        @correlation_id,
        @user_id,
        @session_id,
        @event_name,
        @result_code,
        @success,
        @payload_json
    );
END;
GO


