-- -----------------------------------------------------------------------------
-- 030_auth\usp_logout_all_sessions.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

-- ============================================================
-- Revoke all active sessions (maintenance / emergency logout)
--
-- Terminates every ACTIVE/IDLE session except the caller's own.
-- Uses REVOKED status to distinguish from a normal user logout.
-- Returns count of sessions terminated.
--
-- Audit logging is handled exclusively by BuildResult (C# side).
-- ============================================================

CREATE OR ALTER PROCEDURE auth.usp_logout_all_sessions
(
    @exclude_session_id  UNIQUEIDENTIFIER = NULL,
    @reason              NVARCHAR(255)    = NULL,
    @admin_user_id       INT              = NULL,
    @correlation_id      UNIQUEIDENTIFIER = NULL,

    @result_code         NVARCHAR(20)     OUTPUT,
    @friendly_msg        NVARCHAR(400)    OUTPUT,
    @success             BIT              OUTPUT,
    @terminated_count    INT              OUTPUT
)
AS
BEGIN
    SET NOCOUNT ON;

    SET @success          = 0;
    SET @result_code      = NULL;
    SET @friendly_msg     = NULL;
    SET @terminated_count = 0;

    DECLARE @reason_json NVARCHAR(400) = CONCAT(
        N'{"reason":"admin_logout_all","by":', CAST(@admin_user_id AS NVARCHAR(10)),
        CASE WHEN @reason IS NOT NULL
             THEN CONCAT(N',"note":"', REPLACE(@reason, N'"', N'\"'), N'"')
             ELSE N'' END,
        N'}'
    );

    BEGIN TRY

        --------------------------------------------------------
        -- Permission check (Phase 2c)
        --------------------------------------------------------
        IF auth.fn_has_permission(@admin_user_id, 'sessions.terminate_all') = 0
        BEGIN
            SET @result_code  = 'ERRPERM01';
            SET @friendly_msg = 'You do not have permission for this action.';
            SET @success      = 0;
            RETURN;
        END

        -- Collect active sessions (excluding caller)
        IF OBJECT_ID('tempdb..#ToRevoke') IS NOT NULL
            DROP TABLE #ToRevoke;

        SELECT session_id
        INTO   #ToRevoke
        FROM   auth.user_sessions
        WHERE  is_active = 1
          AND  session_status IN ('ACTIVE', 'IDLE')
          AND  (
                   @exclude_session_id IS NULL
                OR session_id <> @exclude_session_id
               );

        SET @terminated_count = (SELECT COUNT(*) FROM #ToRevoke);

        IF @terminated_count = 0
        BEGIN
            SET @result_code  = 'SUCAUTH09';
            SET @friendly_msg = 'No active sessions to terminate.';
            SET @success      = 1;
            RETURN;
        END

        -- Revoke each session via lifecycle SP
        DECLARE @sid  UNIQUEIDENTIFIER;
        DECLARE @code NVARCHAR(20);
        DECLARE @msg  NVARCHAR(400);

        DECLARE revoke_cursor CURSOR LOCAL FAST_FORWARD FOR
            SELECT session_id FROM #ToRevoke;

        OPEN revoke_cursor;
        FETCH NEXT FROM revoke_cursor INTO @sid;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            EXEC auth.usp_session_set_status
                @session_id    = @sid,
                @to_status     = 'REVOKED',
                @source_app    = 'PeasyWare.Desktop',
                @source_client = 'Admin:LogoutAll',
                @source_ip     = NULL,
                @details       = @reason_json,
                @result_code   = @code OUTPUT,
                @friendly_msg  = @msg  OUTPUT;

            FETCH NEXT FROM revoke_cursor INTO @sid;
        END

        CLOSE revoke_cursor;
        DEALLOCATE revoke_cursor;

        SET @result_code  = 'SUCAUTH09';
        SET @friendly_msg = CONCAT(
            CAST(@terminated_count AS NVARCHAR(10)),
            CASE WHEN @terminated_count = 1 THEN N' session' ELSE N' sessions' END,
            N' terminated.'
        );
        SET @success = 1;

    END TRY
    BEGIN CATCH
        SET @result_code  = 'ERRPROC02';
        SET @friendly_msg = ERROR_MESSAGE();
        SET @success      = 0;
    END CATCH;
END;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\usp_logout.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE auth.usp_logout
(
    @session_id      UNIQUEIDENTIFIER,
    @source_app      NVARCHAR(50),
    @source_client   NVARCHAR(200),
    @source_ip       NVARCHAR(50) = NULL,
    @correlation_id  UNIQUEIDENTIFIER = NULL,

    @result_code     NVARCHAR(20) OUTPUT,
    @friendly_msg    NVARCHAR(400) OUTPUT,
    @success         BIT OUTPUT
)
AS
BEGIN
    SET NOCOUNT ON;

    SET @success = 0;
    SET @result_code = NULL;
    SET @friendly_msg = NULL;

    DECLARE
        @actor_id        INT = TRY_CAST(SESSION_CONTEXT(N'user_id') AS INT),
        @ctx_session_id  UNIQUEIDENTIFIER = TRY_CAST(SESSION_CONTEXT(N'session_id') AS UNIQUEIDENTIFIER),
        @corr_id         UNIQUEIDENTIFIER = COALESCE(@correlation_id, TRY_CAST(SESSION_CONTEXT(N'correlation_id') AS UNIQUEIDENTIFIER)),
        @now             DATETIME2(3) = SYSUTCDATETIME(),

        @session_status  NVARCHAR(20),
        @transition_code NVARCHAR(20),
        @transition_msg  NVARCHAR(400),
        @details         NVARCHAR(MAX);

    BEGIN TRY

        --------------------------------------------------------
        -- Fetch current status
        --------------------------------------------------------
        SELECT @session_status = session_status
        FROM auth.user_sessions
        WHERE session_id = @session_id;

        --------------------------------------------------------
        -- Not found
        --------------------------------------------------------
        IF @session_status IS NULL
        BEGIN
            SET @result_code = 'ERRAUTH06';

            SELECT @friendly_msg = message_template
            FROM operations.error_messages
            WHERE error_code = @result_code;

            GOTO LogAndExit;
        END;

        --------------------------------------------------------
        -- Idempotent success
        --------------------------------------------------------
        IF @session_status IN ('LOGGED_OUT', 'EXPIRED', 'REVOKED')
        BEGIN
            SET @result_code = 'SUCAUTH03';

            SELECT @friendly_msg = message_template
            FROM operations.error_messages
            WHERE error_code = @result_code;

            SET @success = 1;

            GOTO LogAndExit;
        END;

        --------------------------------------------------------
        -- Build details payload (for transition)
        --------------------------------------------------------
        SET @details = (
            SELECT
                @corr_id AS correlation_id,
                'user logout' AS reason
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );

        --------------------------------------------------------
        -- Perform transition
        --------------------------------------------------------
        EXEC auth.usp_session_set_status
            @session_id     = @session_id,
            @to_status      = 'LOGGED_OUT',
            @source_app     = @source_app,
            @source_client  = @source_client,
            @source_ip      = @source_ip,
            @details        = @details,
            @result_code    = @transition_code OUTPUT,
            @friendly_msg   = @transition_msg OUTPUT;

        --------------------------------------------------------
        -- Final response
        --------------------------------------------------------
        IF @transition_code LIKE 'SUC%'
        BEGIN
            SET @result_code = 'SUCAUTH03';

            SELECT @friendly_msg = message_template
            FROM operations.error_messages
            WHERE error_code = @result_code;

            SET @success = 1;
        END
        ELSE
        BEGIN
            SET @result_code  = @transition_code;
            SET @friendly_msg = @transition_msg;
            SET @success = 0;
        END;

LogAndExit:

        --------------------------------------------------------
        -- Payload
        --------------------------------------------------------
        DECLARE @payload_json NVARCHAR(MAX);

        SET @payload_json = (
            SELECT
                @actor_id    AS PerformedBy,
                @session_id  AS TargetSessionId,
                @session_status AS PreviousStatus,
                @result_code AS ResultCode
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );

        --------------------------------------------------------
        -- Mapping
        --------------------------------------------------------
        DECLARE @event_result_code NVARCHAR(50);
        DECLARE @event_success BIT;

        SELECT
            @event_result_code = m.event_result_code,
            @event_success     = m.event_success
        FROM audit.fn_map_user_result(@result_code) m;

        --------------------------------------------------------
        -- Audit
        --------------------------------------------------------
        EXEC audit.usp_log_event
            @correlation_id = @corr_id,
            @user_id        = @actor_id,
            @session_id     = @ctx_session_id,
            @event_name     = 'session.logout',
            @result_code    = @event_result_code,
            @success        = @event_success,
            @payload_json   = @payload_json;

    END TRY
    BEGIN CATCH

        DECLARE @err NVARCHAR(4000) = ERROR_MESSAGE();

        DECLARE @payload_json_error NVARCHAR(MAX);

        SET @payload_json_error = (
            SELECT
                @err AS ErrorMessage,
                @session_id AS TargetSessionId
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );

        EXEC audit.usp_log_event
            @correlation_id = @corr_id,
            @user_id        = @actor_id,
            @session_id     = @ctx_session_id,
            @event_name     = 'system.error.occurred',
            @result_code    = 'UNHANDLED_EXCEPTION',
            @success        = 0,
            @payload_json   = @payload_json_error;

        SET @result_code = 'ERRPROC02';

        SELECT @friendly_msg = message_template
        FROM operations.error_messages
        WHERE error_code = @result_code;

        SET @success = 0;

    END CATCH;
END;
GO

