CREATE OR ALTER PROCEDURE auth.usp_roles_get
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        role_name   AS RoleName,
        description AS Description
    FROM auth.roles
    WHERE is_active      = 1
      AND is_system_role = 0        -- never show system roles in user-facing dropdowns
    ORDER BY role_name;
END;
