-- -----------------------------------------------------------------------------
-- 030_auth\usp_session_touch.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE auth.usp_session_touch
(
    @session_id     UNIQUEIDENTIFIER,
    @source_app     NVARCHAR(50),
    @source_client  NVARCHAR(200),
    @source_ip      NVARCHAR(50) = NULL,

    @result_code    NVARCHAR(20)  OUTPUT,
    @friendly_msg   NVARCHAR(400) OUTPUT,
    @is_alive       BIT           OUTPUT
)
AS
BEGIN
    SET NOCOUNT ON;

    SET @is_alive = 0;
    SET @result_code = NULL;
    SET @friendly_msg = NULL;

    DECLARE
        @user_id INT,
        @is_active BIT,
        @last_seen DATETIME2(3),
        @now DATETIME2(3) = SYSUTCDATETIME(),
        @timeout_minutes INT,
        @session_status NVARCHAR(20),
        @transition_code NVARCHAR(20),
        @transition_msg NVARCHAR(400),
        @client_app NVARCHAR(100),
        @details NVARCHAR(4000);

    SELECT
        @user_id = s.user_id,
        @is_active = s.is_active,
        @last_seen = s.last_seen,
        @session_status = s.session_status,
        @client_app = s.client_app
    FROM auth.user_sessions s
    WHERE s.session_id = @session_id;

    IF @user_id IS NULL
    BEGIN
        SET @result_code = 'ERRAUTH06';
        SET @friendly_msg = operations.fn_get_friendly_message(@result_code);
        RETURN;
    END;

    IF @session_status IS NULL
    BEGIN
        SET @result_code = 'ERRAUTH06';
        SET @friendly_msg = operations.fn_get_friendly_message(@result_code);
        RETURN;
    END;

    IF @session_status IN ('EXPIRED', 'LOGGED_OUT', 'REVOKED')
    BEGIN
        SET @result_code = 'ERRAUTH06';
        SET @friendly_msg = operations.fn_get_friendly_message(@result_code);
        RETURN;
    END;

    SELECT @timeout_minutes =
        COALESCE(c.session_timeout_minutes,
            TRY_CONVERT(INT, os.setting_value))
    FROM operations.settings os
    LEFT JOIN auth.clients c
        ON c.client_name = @client_app
    WHERE os.setting_name = 'auth.session_timeout_minutes';

    IF @timeout_minutes IS NULL OR @timeout_minutes <= 0
        SET @timeout_minutes = 30;

    IF @last_seen IS NULL
       OR @last_seen < DATEADD(MINUTE, -@timeout_minutes, @now)
    BEGIN
        SET @details =
            N'{"last_seen":"'
            + COALESCE(CONVERT(NVARCHAR(30), @last_seen, 126), N'NULL')
            + N'","reason":"touch timeout"}';

        EXEC auth.usp_session_set_status
            @session_id = @session_id,
            @to_status = 'EXPIRED',
            @source_app = @source_app,
            @source_client = @source_client,
            @source_ip = @source_ip,
            @details = @details,
            @result_code = @transition_code OUTPUT,
            @friendly_msg = @transition_msg OUTPUT;

        SET @result_code = 'ERRAUTH06';
        SET @friendly_msg = operations.fn_get_friendly_message(@result_code);
        RETURN;
    END;

    UPDATE auth.user_sessions
    SET
        last_seen = @now,
        session_status = CASE
            WHEN session_status = 'IDLE' THEN 'ACTIVE'
            ELSE session_status
        END,
        is_active = 1
    WHERE session_id = @session_id;

    SET @result_code = 'SUCAUTH02';
    SET @friendly_msg = operations.fn_get_friendly_message(@result_code);
    SET @is_alive = 1;
END;
GO


/* ============================================================
   8. LOGOUT
   ============================================================*/
GO


-- -----------------------------------------------------------------------------
-- 030_auth\usp_set_user_active.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE auth.usp_set_user_active
(
    @user_id        INT,
    @is_active      BIT,

    @result_code    NVARCHAR(20) OUTPUT,
    @friendly_msg   NVARCHAR(400) OUTPUT
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE
        @actor          INT = TRY_CONVERT(INT, SESSION_CONTEXT(N'user_id')),
        @session_id     UNIQUEIDENTIFIER = TRY_CONVERT(UNIQUEIDENTIFIER, SESSION_CONTEXT(N'session_id')),
        @correlation_id UNIQUEIDENTIFIER = TRY_CONVERT(UNIQUEIDENTIFIER, SESSION_CONTEXT(N'correlation_id')),
        @now            DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY

        --------------------------------------------------------
        -- Permission check (Phase 2c)
        --------------------------------------------------------
        IF auth.fn_has_permission(@actor, 'users.manage') = 0
        BEGIN
            SET @result_code = 'ERRPERM01';

            SELECT @friendly_msg = message_template
            FROM operations.error_messages
            WHERE error_code = @result_code;

            GOTO LogAndExit;
        END;

        --------------------------------------------------------
        -- Validate target user
        --------------------------------------------------------
        IF NOT EXISTS (
            SELECT 1
            FROM auth.users
            WHERE id = @user_id
        )
        BEGIN
            SET @result_code = 'ERRUSR01';

            SELECT @friendly_msg = message_template
            FROM operations.error_messages
            WHERE error_code = @result_code;

            GOTO LogAndExit;
        END;

        --------------------------------------------------------
        -- Perform update
        --------------------------------------------------------
        UPDATE auth.users
        SET
            is_active   = @is_active,
            updated_at  = @now,
            updated_by  = @actor
        WHERE id = @user_id;

        --------------------------------------------------------
        -- Success
        --------------------------------------------------------
        SET @result_code = 'SUCUSR01';

        SELECT @friendly_msg = message_template
        FROM operations.error_messages
        WHERE error_code = @result_code;

LogAndExit:

        --------------------------------------------------------
        -- Payload
        --------------------------------------------------------
        DECLARE @payload_json NVARCHAR(MAX);

        SET @payload_json = (
            SELECT
                @actor       AS PerformedBy,
                @user_id     AS TargetUserId,
                @is_active   AS IsActive,
                @result_code AS ResultCode
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );

        --------------------------------------------------------
        -- Mapping (CENTRALISED)
        --------------------------------------------------------
        DECLARE @event_result_code NVARCHAR(50);
        DECLARE @event_success BIT;

        SELECT
            @event_result_code = m.event_result_code,
            @event_success     = m.event_success
        FROM audit.fn_map_user_result(@result_code) m;

        --------------------------------------------------------
        -- Audit
        --------------------------------------------------------
        EXEC audit.usp_log_event
            @correlation_id = @correlation_id,
            @user_id        = @actor,
            @session_id     = @session_id,
            @event_name     = 'user.status.updated',
            @result_code    = @event_result_code,
            @success        = @event_success,
            @payload_json   = @payload_json;

    END TRY
    BEGIN CATCH

        DECLARE @err NVARCHAR(4000) = ERROR_MESSAGE();

        DECLARE @payload_json_error NVARCHAR(MAX);

        SET @payload_json_error = (
            SELECT
                @err AS ErrorMessage,
                @user_id AS TargetUserId
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );

        EXEC audit.usp_log_event
            @correlation_id = @correlation_id,
            @user_id        = @actor,
            @session_id     = @session_id,
            @event_name     = 'system.error.occurred',
            @result_code    = 'UNHANDLED_EXCEPTION',
            @success        = 0,
            @payload_json   = @payload_json_error;

        SET @result_code = 'ERRPROC02';

        SELECT @friendly_msg = message_template
        FROM operations.error_messages
        WHERE error_code = @result_code;

    END CATCH;
END;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\usp_update_user.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE auth.usp_update_user
(
    @user_id        INT,
    @display_name   NVARCHAR(100)    = NULL,
    @email          NVARCHAR(200)    = NULL,
    @role_name      NVARCHAR(50)     = NULL,
    @admin_user_id  INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        --------------------------------------------------------
        -- Permission check (Phase 2c)
        --------------------------------------------------------
        IF auth.fn_has_permission(@admin_user_id, 'users.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = @user_id)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRAUTHUSR05' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Resolve role if provided
        DECLARE @role_id INT = NULL;
        IF @role_name IS NOT NULL
        BEGIN
            SELECT @role_id = id
            FROM auth.roles
            WHERE role_name = @role_name COLLATE Latin1_General_CS_AS;

            IF @role_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRAUTHUSR06' AS result_code;
                ROLLBACK; RETURN;
            END
        END

        -- Update user profile fields
        UPDATE auth.users
        SET
            display_name = ISNULL(@display_name, display_name),
            email        = ISNULL(@email,        email),
            updated_at   = SYSUTCDATETIME(),
            updated_by   = @admin_user_id
        WHERE id = @user_id;

        -- Update role via user_roles join table
        IF @role_id IS NOT NULL
        BEGIN
            -- Remove existing role assignments then insert the new one
            DELETE FROM auth.user_roles WHERE user_id = @user_id;
            INSERT INTO auth.user_roles (user_id, role_id) VALUES (@user_id, @role_id);
        END

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCAUTH08' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRAUTH99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\v_active_sessions.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW auth.v_active_sessions
AS
SELECT
    s.session_id,
    u.username,
    s.client_app,
    s.client_info,
    s.last_seen,
    s.is_active
FROM auth.user_sessions s
JOIN auth.users u
    ON u.id = s.user_id
WHERE s.is_active = 1;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\v_session_forensic.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW auth.v_session_forensic
AS
SELECT
    s.session_id,
    s.is_active,
    s.login_time,
    s.last_seen,
    u.id            AS user_id,
    u.username,
    u.display_name,
    s.client_app,
    s.client_info,
    la.ip_address,
    la.os_info,
    la.correlation_id
FROM auth.user_sessions s
JOIN auth.users u ON u.id = s.user_id
OUTER APPLY
(
    SELECT TOP (1)
        a.ip_address,
        a.os_info,
        a.correlation_id
    FROM auth.login_attempts a
    WHERE a.session_id = s.session_id
      AND a.success = 1
    ORDER BY a.attempt_time DESC
) la;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\v_user_permissions.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

-------------------------------------------------------------------------
-- auth.v_user_permissions
-- Flattened user -> permission list, one query at login (2b step 3).
-- Only active users, active roles, active permissions are surfaced.
-------------------------------------------------------------------------
CREATE OR ALTER VIEW auth.v_user_permissions
AS

SELECT
    u.id    AS user_id,
    u.username,
    p.permission_key

FROM auth.users u

JOIN auth.user_roles ur
    ON ur.user_id = u.id

JOIN auth.roles r
    ON r.id = ur.role_id
    AND r.is_active = 1

JOIN auth.role_permissions rp
    ON rp.role_id = r.id

JOIN auth.permissions p
    ON p.id = rp.permission_id
    AND p.is_active = 1

WHERE u.is_active = 1;
GO


-- -----------------------------------------------------------------------------
-- 030_auth\v_users_admin.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW auth.v_users_admin
AS

SELECT
    u.id,
    u.username,
    u.display_name,

    -- Role (defensive)
    COALESCE(r.role_name, '[MISSING ROLE]') AS role_name,

    u.email,

    -- ONLINE if at least one active session exists
    CAST(
        CASE
            WHEN MAX(CASE WHEN s.is_active = 1 THEN 1 ELSE 0 END) = 1
                THEN 1
            ELSE 0
        END
    AS bit) AS is_online,

    -- Most recent last_seen across ALL sessions
    MAX(s.last_seen) AS last_last_seen,

    u.is_active,
    u.must_change_password,
    u.failed_attempts,
    u.lockout_until,
    u.password_expires_at,

    u.created_at,
    u.created_by,
    u.updated_at,
    u.updated_by

FROM auth.users u

-- users may exist without a role (temporarily or due to config drift)
LEFT JOIN auth.user_roles ur
    ON u.id = ur.user_id

LEFT JOIN auth.roles r
    ON ur.role_id = r.id

LEFT JOIN auth.user_sessions s
    ON u.id = s.user_id

WHERE auth.fn_is_system_user(u.id) = 0

GROUP BY
    u.id,
    u.username,
    u.display_name,
    COALESCE(r.role_name, '[MISSING ROLE]'),
    u.email,
    u.is_active,
    u.must_change_password,
    u.failed_attempts,
    u.lockout_until,
    u.password_expires_at,
    u.created_at,
    u.created_by,
    u.updated_at,
    u.updated_by;
GO


