SET QUOTED_IDENTIFIER ON;
GO

-- ============================================================
-- auth.v_clients — client application registrations
-- ============================================================
CREATE OR ALTER VIEW auth.v_clients
AS
SELECT
    c.client_name,
    c.session_timeout_minutes,
    c.max_concurrent_sessions,
    c.is_active,
    c.description,
    c.created_at,
    u.username AS created_by_username
FROM auth.clients c
LEFT JOIN auth.users u ON u.id = c.created_by;
GO

-- ============================================================
-- usp_create_client
-- ============================================================
CREATE OR ALTER PROCEDURE auth.usp_create_client
(
    @client_name             NVARCHAR(100),
    @session_timeout_minutes INT              = NULL,
    @max_concurrent_sessions INT              = NULL,
    @description             NVARCHAR(255)    = NULL,
    @user_id                 INT              = NULL,
    @session_id              UNIQUEIDENTIFIER = NULL,
    @correlation_id          UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    BEGIN TRY
        BEGIN TRAN;

        IF EXISTS (SELECT 1 FROM auth.clients WHERE client_name = @client_name COLLATE Latin1_General_CS_AS)
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRCLI01' AS result_code; ROLLBACK; RETURN; END

        INSERT INTO auth.clients
            (client_name, session_timeout_minutes, max_concurrent_sessions, description, created_by)
        VALUES
            (@client_name, @session_timeout_minutes, @max_concurrent_sessions, @description, @user_id);

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCCLI01' AS result_code;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRCLI99' AS result_code;
    END CATCH
END;
GO

-- ============================================================
-- usp_update_client
-- ============================================================
CREATE OR ALTER PROCEDURE auth.usp_update_client
(
    @client_name             NVARCHAR(100),
    @session_timeout_minutes INT              = NULL,
    @clear_timeout           BIT              = 0,
    @max_concurrent_sessions INT              = NULL,
    @clear_max_sessions      BIT              = 0,
    @description             NVARCHAR(255)    = NULL,
    @clear_desc              BIT              = 0,
    @user_id                 INT              = NULL,
    @session_id              UNIQUEIDENTIFIER = NULL,
    @correlation_id          UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    BEGIN TRY
        BEGIN TRAN;

        IF NOT EXISTS (SELECT 1 FROM auth.clients WHERE client_name = @client_name COLLATE Latin1_General_CS_AS)
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRCLI02' AS result_code; ROLLBACK; RETURN; END

        UPDATE auth.clients
        SET
            session_timeout_minutes = CASE WHEN @clear_timeout    = 1 THEN NULL
                                           WHEN @session_timeout_minutes IS NOT NULL THEN @session_timeout_minutes
                                           ELSE session_timeout_minutes END,
            max_concurrent_sessions = CASE WHEN @clear_max_sessions = 1 THEN NULL
                                           WHEN @max_concurrent_sessions IS NOT NULL THEN @max_concurrent_sessions
                                           ELSE max_concurrent_sessions END,
            description             = CASE WHEN @clear_desc = 1 THEN NULL
                                           WHEN @description IS NOT NULL THEN @description
                                           ELSE description END
        WHERE client_name = @client_name COLLATE Latin1_General_CS_AS;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCCLI02' AS result_code;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRCLI99' AS result_code;
    END CATCH
END;
GO

-- ============================================================
-- usp_deactivate_client / usp_reactivate_client
-- ============================================================
CREATE OR ALTER PROCEDURE auth.usp_deactivate_client
(
    @client_name    NVARCHAR(100),
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    BEGIN TRY
        BEGIN TRAN;

        IF NOT EXISTS (SELECT 1 FROM auth.clients WHERE client_name = @client_name COLLATE Latin1_General_CS_AS AND is_active = 1)
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRCLI02' AS result_code; ROLLBACK; RETURN; END

        UPDATE auth.clients SET is_active = 0 WHERE client_name = @client_name COLLATE Latin1_General_CS_AS;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCCLI03' AS result_code;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRCLI99' AS result_code;
    END CATCH
END;
GO

CREATE OR ALTER PROCEDURE auth.usp_reactivate_client
(
    @client_name    NVARCHAR(100),
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    BEGIN TRY
        BEGIN TRAN;

        IF NOT EXISTS (SELECT 1 FROM auth.clients WHERE client_name = @client_name COLLATE Latin1_General_CS_AS AND is_active = 0)
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRCLI02' AS result_code; ROLLBACK; RETURN; END

        UPDATE auth.clients SET is_active = 1 WHERE client_name = @client_name COLLATE Latin1_General_CS_AS;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCCLI04' AS result_code;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRCLI99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 035_post_auth\v_event_log.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW audit.v_event_log
AS
SELECT
    t.trace_id,
    t.occurred_at,
    t.level,
    t.action,
    -- Session context
    t.user_id,
    u.username,
    t.session_id,
    t.correlation_id,
    -- Parsed from JSON payload
    JSON_VALUE(t.payload_json, '$.Session.SourceApp')    AS source_app,
    JSON_VALUE(t.payload_json, '$.Session.SourceClient') AS source_client,
    -- Common outcome fields
    JSON_VALUE(t.payload_json, '$.Data.ResultCode')      AS result_code,
    JSON_VALUE(t.payload_json, '$.Data.Success')         AS success,
    -- Full payload for detail view
    t.payload_json
FROM audit.trace_logs t
LEFT JOIN auth.users u ON u.id = t.user_id;
GO
PRINT 'audit.v_event_log created.';
GO


-- -----------------------------------------------------------------------------
-- 035_post_auth\v_location_changes.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW audit.v_location_changes
AS
SELECT
    t.trace_id,
    t.occurred_at,
    u.username,
    -- Normalise action to a friendly label
    CASE t.action
        WHEN 'Location.Create'     THEN 'CREATE'
        WHEN 'Location.Update'     THEN 'UPDATE'
        WHEN 'Location.Lock'       THEN 'LOCK'
        WHEN 'Location.Unlock'     THEN 'UNLOCK'
        WHEN 'Location.Deactivate' THEN 'DEACTIVATE'
        WHEN 'Location.Reactivate' THEN 'REACTIVATE'
        ELSE t.action
    END                                                                     AS action_type,

    -- Bin code (after for create/update, current for others)
    COALESCE(
        JSON_VALUE(t.payload_json, '$.Data.Outcome.BinCode'),
        JSON_VALUE(t.payload_json, '$.Data.Outcome.After.BinCode')
    )                                                                       AS bin_code,

    -- Before state (only meaningful on UPDATE)
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.BinCode')            AS bin_code_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.StorageTypeCode')    AS type_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.SectionCode')        AS section_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.ZoneCode')           AS zone_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.Capacity')  AS INT) AS capacity_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsActive')  AS BIT) AS active_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsLocked')  AS BIT) AS locked_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.Notes')              AS notes_before,

    -- After state (only meaningful on UPDATE)
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.BinCode')             AS bin_code_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.StorageTypeCode')     AS type_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.SectionCode')         AS section_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.ZoneCode')            AS zone_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.Capacity')   AS INT) AS capacity_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.Notes')               AS notes_after,

    -- Lock/deactivate reason
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Reason')                    AS reason

FROM audit.trace_logs t
LEFT JOIN auth.users u ON u.id = t.user_id
WHERE t.action IN (
    'Location.Create',
    'Location.Update',
    'Location.Lock',
    'Location.Unlock',
    'Location.Deactivate',
    'Location.Reactivate'
)
-- Only include the rich C# BuildResult rows (have $.Timestamp)
-- The SP-level rows are minimal duplicates without session context
AND JSON_VALUE(t.payload_json, '$.Timestamp') IS NOT NULL;
GO
PRINT 'audit.v_location_changes created.';
GO


-- -----------------------------------------------------------------------------
-- 035_post_auth\v_settings.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW operations.v_settings
AS
SELECT
    s.setting_name,
    s.display_name,
    s.category,
    c.display_name AS category_name,
    c.display_order AS category_order,
    s.display_order,

    s.setting_value,
    s.data_type,
    s.validation_rule,
    s.description,
    s.is_sensitive,
    s.requires_restart,

    s.created_at,
    s.created_by,
    s.updated_at,
    s.updated_by,
    u.username AS updated_by_username,

    CASE WHEN s.data_type = 'bool' THEN CAST(1 AS bit) ELSE CAST(0 AS bit) END AS is_boolean,

    CASE WHEN JSON_VALUE(s.validation_rule,'$.type') = 'enum'
         THEN CAST(1 AS bit) ELSE CAST(0 AS bit) END AS is_enum,

    CASE WHEN JSON_VALUE(s.validation_rule,'$.type') = 'range'
         THEN CAST(1 AS bit) ELSE CAST(0 AS bit) END AS is_range,

    TRY_CONVERT(int, JSON_VALUE(s.validation_rule,'$.min')) AS range_min,
    TRY_CONVERT(int, JSON_VALUE(s.validation_rule,'$.max')) AS range_max

FROM operations.settings s
LEFT JOIN operations.setting_categories c
    ON s.category = c.category
LEFT JOIN auth.users u
    ON s.updated_by = u.id;

GO

ALTER FUNCTION auth.fn_is_session_expired
(
    @last_seen       datetime2(3),
    @timeout_minutes int
)
RETURNS bit
AS
BEGIN
    IF @last_seen IS NULL OR @timeout_minutes IS NULL OR @timeout_minutes <= 0
        RETURN 1;

    IF DATEDIFF(MINUTE, @last_seen, SYSUTCDATETIME()) >= @timeout_minutes
        RETURN 1;

    RETURN 0;
END;
GO


-- -----------------------------------------------------------------------------
-- 035_post_auth\v_sku_changes.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW audit.v_sku_changes
AS
SELECT
    t.trace_id,
    t.occurred_at,
    u.username,
    CASE t.action
        WHEN 'Sku.Create' THEN 'INSERT'
        WHEN 'Sku.Update' THEN 'UPDATE'
    END                                                                       AS action_type,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.SkuCode')                     AS sku_code,

    -- Before state (NULL on INSERT)
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.SkuDescription')       AS desc_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.Ean')                  AS ean_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.UomCode')              AS uom_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.WeightPerUnit')      AS DECIMAL(10,3)) AS weight_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.StandardHuQuantity') AS INT)           AS hu_qty_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsBatchRequired')    AS BIT)           AS batch_req_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsFullHuRequired')   AS BIT)           AS full_hu_req_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsHazardous')        AS BIT)           AS hazardous_before,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.IsActive')           AS BIT)           AS active_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.StorageTypeCode')      AS storage_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.SectionCode')          AS section_before,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.Before.OwnerPartyCode')       AS owner_before,

    -- After state
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.SkuDescription')        AS desc_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.Ean')                   AS ean_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.UomCode')               AS uom_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.WeightPerUnit')       AS DECIMAL(10,3)) AS weight_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.StandardHuQuantity')  AS INT)           AS hu_qty_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.IsBatchRequired')     AS BIT)           AS batch_req_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.IsFullHuRequired')    AS BIT)           AS full_hu_req_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.IsHazardous')         AS BIT)           AS hazardous_after,
    TRY_CAST(JSON_VALUE(t.payload_json, '$.Data.Outcome.After.IsActive')            AS BIT)           AS active_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.StorageTypeCode')       AS storage_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.SectionCode')           AS section_after,
    JSON_VALUE(t.payload_json, '$.Data.Outcome.After.OwnerPartyCode')        AS owner_after

FROM audit.trace_logs t
LEFT JOIN auth.users u ON u.id = t.user_id
WHERE t.action IN ('Sku.Create', 'Sku.Update');
GO


-- -----------------------------------------------------------------------------
-- 035_post_auth\v_user_activity.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW audit.v_user_activity
AS
-- ── Source 1: Trigger-based user_changes ──────────────────────────────────
SELECT
    CAST(uc.audit_id AS BIGINT)             AS event_id,
    uc.changed_at                           AS occurred_at,
    'TRIGGER'                               AS source,
    uc.action                               AS event_type,
    -- Subject: the user who was changed
    uc.user_id                              AS subject_user_id,
    subject.username                        AS subject_username,
    -- Actor: who made the change
    uc.changed_by                           AS actor_user_id,
    actor.username                          AS actor_username,
    uc.session_id,
    -- Detail
    CASE uc.action
        WHEN 'SET_ACTIVE'
            THEN CONCAT('is_active: ', CAST(uc.old_is_active AS NVARCHAR(1)),
                        ' → ', CAST(uc.new_is_active AS NVARCHAR(1)))
        ELSE ISNULL(uc.details, '')
    END                                     AS detail,
    NULL                                    AS result_code,
    NULL                                    AS source_app
FROM audit.user_changes uc
JOIN auth.users subject ON subject.id = uc.user_id
LEFT JOIN auth.users actor   ON actor.id   = uc.changed_by

UNION ALL

-- ── Source 2: Trace log user events ───────────────────────────────────────
SELECT
    CAST(t.trace_id AS BIGINT)              AS event_id,
    t.occurred_at,
    'TRACE'                                 AS source,
    t.action                                AS event_type,
    -- Subject: the user the action is about
    t.user_id                               AS subject_user_id,
    u.username                              AS subject_username,
    -- Actor: same as subject for self-service events
    t.user_id                               AS actor_user_id,
    u.username                              AS actor_username,
    t.session_id,
    -- Detail from JSON
    ISNULL(
        JSON_VALUE(t.payload_json, '$.Data.ResultCode'),
        ''
    )                                       AS detail,
    JSON_VALUE(t.payload_json, '$.Data.ResultCode') AS result_code,
    JSON_VALUE(t.payload_json, '$.Session.SourceApp') AS source_app
FROM audit.trace_logs t
LEFT JOIN auth.users u ON u.id = t.user_id
WHERE t.action IN (
    'user.created',
    'user.password.changed',
    'AuthService.PasswordChange.Start',
    'AuthService.PasswordChange.Result',
    'AuthService.Login.Start',
    'AuthService.Login.Result',
    'Session.Start',
    'Session.Logout'
);
GO
PRINT 'audit.v_user_activity created.';
GO


-- -----------------------------------------------------------------------------
-- 040_core\010_tables.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE TABLE core.parties
(
    party_id        INT IDENTITY(1,1) PRIMARY KEY,

    -- Stable external reference (e.g. SAP BP / Vendor / Customer code)
    party_code      NVARCHAR(50)  NOT NULL,

    -- Legal registered name (finance / compliance)
    legal_name      NVARCHAR(200) NOT NULL,

    -- Friendly operational name (what users see)
    display_name    NVARCHAR(200) NOT NULL,

    -- ISO country code (e.g. GB, HU)
    country_code    CHAR(2)       NULL,

    -- Tax / VAT identifier if applicable
    tax_id          NVARCHAR(50)  NULL,

    -- Soft-enable flag (do not delete historical parties)
    is_active       BIT           NOT NULL DEFAULT (1),

    -- Audit
    created_at      DATETIME2(3)  NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by      INT           NULL,
    updated_at      DATETIME2(3)  NULL,
    updated_by      INT           NULL,

    CONSTRAINT uq_parties_code UNIQUE (party_code)
);

/* ============================================================
   core.party_roles
   ------------------------------------------------------------
   Assigns functional roles to parties.

   A party may have multiple roles simultaneously
   (e.g. SUPPLIER + HAULIER).

   Role codes are intentionally free-text for now.
   ============================================================ */
CREATE TABLE core.party_roles
(
    party_id    INT          NOT NULL,
    role_code   NVARCHAR(50) NOT NULL, -- SUPPLIER, CUSTOMER, HAULIER, OWNER

    assigned_at DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    assigned_by      INT           NULL,
    updated_at      DATETIME2(3)  NULL,
    updated_by      INT           NULL,

    CONSTRAINT pk_party_roles
        PRIMARY KEY (party_id, role_code),

    CONSTRAINT fk_party_roles_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id)
);

/* ============================================================
   core.party_addresses
   ------------------------------------------------------------
   Physical or logical addresses associated with a party.
   Can be reused across inbound, outbound, billing, etc.
   ============================================================ */
CREATE TABLE core.party_addresses
(
    address_id        INT IDENTITY(1,1) PRIMARY KEY,

    -- Owning party
    party_id          INT NOT NULL,

    -- Address usage / intent
    -- e.g. SHIP_FROM, SHIP_TO, BILL_TO, HQ, YARD
    address_type      NVARCHAR(50) NOT NULL,

    -- Free-text address fields (intentionally simple)
    line_1            NVARCHAR(200) NOT NULL,
    line_2            NVARCHAR(200) NULL,
    city              NVARCHAR(100) NULL,
    region            NVARCHAR(100) NULL,
    postal_code       NVARCHAR(50)  NULL,
    country_code      CHAR(2)       NOT NULL,

    -- Optional operational hints
    dock_info         NVARCHAR(200) NULL, -- gate, dock, yard notes
    instructions      NVARCHAR(400) NULL, -- receiving notes, access rules

    -- Flags
    is_primary        BIT NOT NULL DEFAULT (0),
    is_active         BIT NOT NULL DEFAULT (1),

    -- Audit
    created_at        DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by        INT          NULL,
    updated_at        DATETIME2(3) NULL,
    updated_by        INT          NULL,

    CONSTRAINT fk_party_addresses_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id)
);

/* ============================================================
   suppliers.suppliers
   ------------------------------------------------------------
   Supplier-specific attributes extending core.parties.
   ============================================================ */
CREATE TABLE suppliers.suppliers
(
    party_id             INT PRIMARY KEY,
    supplier_type        NVARCHAR(50) NULL,  -- RAW, PACKAGING, 3PL
    default_lead_days    INT          NULL,
    preferred_haulier_id INT          NULL,

    created_at    DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by    INT          NULL,
    updated_at    DATETIME2(3) NULL,
    updated_by    INT          NULL,

    CONSTRAINT fk_suppliers_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id),

    CONSTRAINT fk_suppliers_haulier
        FOREIGN KEY (preferred_haulier_id)
        REFERENCES core.parties(party_id)
);


/* ============================================================
   customers.customers
   ------------------------------------------------------------
   Customer-specific attributes extending core.parties.
   ============================================================ */
CREATE TABLE customers.customers
(
    party_id               INT PRIMARY KEY,
    customer_type          NVARCHAR(50) NULL, -- RETAIL, WHOLESALE, EXPORT
    default_delivery_days  INT          NULL,
    preferred_haulier_id   INT          NULL,
    allow_crossdock        BIT NOT NULL DEFAULT (0),

    created_at    DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by    INT          NULL,
    updated_at    DATETIME2(3) NULL,
    updated_by    INT          NULL,

    CONSTRAINT fk_customers_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id),

    CONSTRAINT fk_customers_haulier
        FOREIGN KEY (preferred_haulier_id)
        REFERENCES core.parties(party_id)
);


/* ============================================================
   logistics.hauliers
   ------------------------------------------------------------
   Haulier-specific attributes extending core.parties.
   ============================================================ */
CREATE TABLE logistics.hauliers
(
    party_id              INT PRIMARY KEY,
    haulier_type          NVARCHAR(50) NULL, -- INTERNAL, CONTRACTED
    default_vehicle_type  NVARCHAR(50) NULL, -- CURTAIN, BOX, FRIDGE
    requires_timeslot     BIT NOT NULL DEFAULT (0),
    notes                 NVARCHAR(500) NULL,

    CONSTRAINT fk_hauliers_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id)
);


/* ============================================================
   core.party_contacts
   ============================================================ */
CREATE TABLE core.party_contacts
(
    contact_id    INT IDENTITY(1,1) PRIMARY KEY,
    party_id      INT NOT NULL,

    contact_role  NVARCHAR(50) NULL,
    contact_name  NVARCHAR(200) NULL,
    email         NVARCHAR(200) NULL,
    phone         NVARCHAR(50)  NULL,

    is_primary    BIT NOT NULL DEFAULT (0),
    is_active     BIT NOT NULL DEFAULT (1),

    created_at    DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by    INT          NULL,
    updated_at    DATETIME2(3) NULL,
    updated_by    INT          NULL,

    CONSTRAINT fk_party_contacts_party
        FOREIGN KEY (party_id)
        REFERENCES core.parties(party_id)
);


/* ============================================================
   audit.party_changes
   ------------------------------------------------------------
   RULE: audit tables carry IDs, never enforced FKs.
   party_id is a point-in-time reference, not a live relationship.
   An enforced FK here makes it impossible to audit the deletion
   of a party (the trigger INSERT fires after the parent row is
   gone) and blocks legitimate cleanup.
   ============================================================ */
CREATE TABLE audit.party_changes
(
    audit_id     BIGINT IDENTITY PRIMARY KEY,
    party_id     INT NOT NULL,

    action       NVARCHAR(50) NOT NULL,
    details      NVARCHAR(500) NULL,

    changed_at   DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    changed_by   INT NULL,
    session_id   UNIQUEIDENTIFIER NULL
);

CREATE NONCLUSTERED INDEX IX_party_changes_party_time
    ON audit.party_changes (party_id, changed_at DESC);
GO


-- -----------------------------------------------------------------------------
-- 040_core\tr_parties_audit.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER TRIGGER core.tr_parties_audit
ON core.parties
AFTER INSERT, UPDATE, DELETE
AS
BEGIN
    SET NOCOUNT ON;

    INSERT INTO audit.party_changes
    (
        party_id,
        action,
        details,
        changed_by,
        session_id
    )
    SELECT
        COALESCE(i.party_id, d.party_id),

        CASE
            WHEN d.party_id IS NULL THEN 'CREATE_PARTY'
            WHEN i.party_id IS NULL THEN 'DELETE_PARTY'
            WHEN d.is_active <> i.is_active THEN 'SET_ACTIVE'
            ELSE 'UPDATE_PARTY'
        END,

        CONCAT(
            'code=', COALESCE(i.party_code, d.party_code),
            '; name=', COALESCE(i.display_name, d.display_name)
        ),

        TRY_CAST(SESSION_CONTEXT(N'user_id') AS INT),
        TRY_CAST(SESSION_CONTEXT(N'session_id') AS UNIQUEIDENTIFIER)

    FROM inserted i
    FULL JOIN deleted d
        ON d.party_id = i.party_id;
END;
GO


-- -----------------------------------------------------------------------------
-- 040_core\usp_create_party.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE core.usp_create_party
(
    @party_code     NVARCHAR(50),
    @legal_name     NVARCHAR(200),
    @display_name   NVARCHAR(200),
    @country_code   CHAR(2)          = NULL,
    @tax_id         NVARCHAR(50)     = NULL,
    @roles          NVARCHAR(500)    = NULL,   -- comma-separated: 'SUPPLIER,CUSTOMER'
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF EXISTS (SELECT 1 FROM core.parties WHERE party_code = @party_code COLLATE Latin1_General_CS_AS)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPARTY01' AS result_code, NULL AS party_id;
            ROLLBACK; RETURN;
        END

        INSERT INTO core.parties
            (party_code, legal_name, display_name, country_code, tax_id,
             is_active, created_at, created_by)
        VALUES
            (@party_code, @legal_name, @display_name, @country_code, @tax_id,
             1, SYSUTCDATETIME(), @user_id);

        DECLARE @party_id INT = SCOPE_IDENTITY();

        -- Insert roles from comma-separated list
        IF @roles IS NOT NULL AND LEN(TRIM(@roles)) > 0
        BEGIN
            INSERT INTO core.party_roles (party_id, role_code, assigned_at, assigned_by)
            SELECT
                @party_id,
                TRIM(value),
                SYSUTCDATETIME(),
                @user_id
            FROM STRING_SPLIT(@roles, ',')
            WHERE LEN(TRIM(value)) > 0;
        END

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCPARTY01' AS result_code, @party_id AS party_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRPARTY99' AS result_code, NULL AS party_id;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 040_core\usp_update_party.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE core.usp_update_party
(
    @party_id       INT,
    @legal_name     NVARCHAR(200),
    @display_name   NVARCHAR(200),
    @country_code   CHAR(2)          = NULL,
    @tax_id         NVARCHAR(50)     = NULL,
    @is_active      BIT              = 1,
    @roles          NVARCHAR(500)    = NULL,   -- full replacement of roles
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF NOT EXISTS (SELECT 1 FROM core.parties WHERE party_id = @party_id)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPARTY02' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE core.parties
        SET legal_name   = @legal_name,
            display_name = @display_name,
            country_code = @country_code,
            tax_id       = @tax_id,
            is_active    = @is_active,
            updated_at   = SYSUTCDATETIME(),
            updated_by   = @user_id
        WHERE party_id = @party_id;

        -- Full role replacement if provided
        IF @roles IS NOT NULL
        BEGIN
            DELETE FROM core.party_roles WHERE party_id = @party_id;

            IF LEN(TRIM(@roles)) > 0
            BEGIN
                INSERT INTO core.party_roles (party_id, role_code, assigned_at, assigned_by)
                SELECT
                    @party_id,
                    TRIM(value),
                    SYSUTCDATETIME(),
                    @user_id
                FROM STRING_SPLIT(@roles, ',')
                WHERE LEN(TRIM(value)) > 0;
            END
        END

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCPARTY02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRPARTY99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 040_core\v_parties.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW core.v_parties
AS
SELECT
    p.party_id,
    p.party_code,
    p.legal_name,
    p.display_name,
    p.country_code,
    p.tax_id,
    p.is_active,
    p.created_at,
    cu.username                 AS created_by_username,
    p.updated_at,
    uu.username                 AS updated_by_username,
    -- Aggregated roles as comma-separated string for display
    ISNULL(
        STUFF((
            SELECT ', ' + pr2.role_code
            FROM core.party_roles pr2
            WHERE pr2.party_id = p.party_id
            ORDER BY pr2.role_code
            FOR XML PATH(''), TYPE
        ).value('.', 'NVARCHAR(MAX)'), 1, 2, ''),
    '') AS roles,
    -- Individual role flags for filtering
    CAST(MAX(CASE WHEN pr.role_code = 'SUPPLIER'  THEN 1 ELSE 0 END) AS BIT) AS is_supplier,
    CAST(MAX(CASE WHEN pr.role_code = 'CUSTOMER'  THEN 1 ELSE 0 END) AS BIT) AS is_customer,
    CAST(MAX(CASE WHEN pr.role_code = 'HAULIER'   THEN 1 ELSE 0 END) AS BIT) AS is_haulier,
    CAST(MAX(CASE WHEN pr.role_code = 'OWNER'     THEN 1 ELSE 0 END) AS BIT) AS is_owner,
    CAST(MAX(CASE WHEN pr.role_code = 'WAREHOUSE' THEN 1 ELSE 0 END) AS BIT) AS is_warehouse
FROM core.parties p
LEFT JOIN core.party_roles pr  ON pr.party_id = p.party_id
LEFT JOIN auth.users cu        ON cu.id = p.created_by
LEFT JOIN auth.users uu        ON uu.id = p.updated_by
GROUP BY
    p.party_id, p.party_code, p.legal_name, p.display_name,
    p.country_code, p.tax_id, p.is_active,
    p.created_at, cu.username,
    p.updated_at, uu.username;
GO
PRINT 'core.v_parties created.';
GO


-- -----------------------------------------------------------------------------
-- 050_locations\010_tables.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE TABLE locations.storage_types
(
    storage_type_id   INT IDENTITY(1,1) PRIMARY KEY,

    -- Stable code used by SKU preferences & logic (e.g. RACK, BULK)
    storage_type_code NVARCHAR(50) NOT NULL,

    -- Human-friendly name
    storage_type_name NVARCHAR(100) NOT NULL,

    -- Optional operational description
    description       NVARCHAR(255) NULL,

    is_active         BIT NOT NULL DEFAULT (1),

    created_at        DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by        INT NULL,
    updated_at        DATETIME2(3) NULL,
    updated_by        INT NULL,

    CONSTRAINT uq_storage_types_code
        UNIQUE (storage_type_code)
);

/* ============================================================
   locations.storage_sections
   ------------------------------------------------------------
   Sub-division within a storage type.
   Sections are scoped to a single storage type.
   ============================================================ */
CREATE TABLE locations.storage_sections
(
    storage_section_id INT IDENTITY(1,1) PRIMARY KEY,
    section_code       NVARCHAR(50)  NOT NULL,
    section_name       NVARCHAR(100) NOT NULL,
    description        NVARCHAR(255) NULL,
    is_active          BIT          NOT NULL DEFAULT (1),
    created_at         DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by         INT NULL,
    updated_at         DATETIME2(3) NULL,
    updated_by         INT NULL
);


/* ============================================================
   locations.zones
   ------------------------------------------------------------
   Operational grouping for travel paths, load balancing,
   and putaway optimisation (e.g. AISLE_01, BULK_ZONE_A).
   ============================================================ */
CREATE TABLE locations.zones
(
    zone_id        INT IDENTITY(1,1) PRIMARY KEY,
    zone_code      NVARCHAR(50)  NOT NULL,
    zone_name      NVARCHAR(100) NOT NULL,
    description    NVARCHAR(255) NULL,
    is_active      BIT          NOT NULL DEFAULT (1),
    created_at     DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by     INT NULL,
    updated_at     DATETIME2(3) NULL,
    updated_by     INT NULL,
    CONSTRAINT uq_zones_code UNIQUE (zone_code)
);

/* ============================================================
   locations.bins
   ------------------------------------------------------------
   Physical storage units.
   This is the ONLY place inventory can reside.
   ============================================================ */
CREATE TABLE locations.bins
(
    bin_id              INT IDENTITY(1,1) PRIMARY KEY,
    bin_code            NVARCHAR(100) NOT NULL,
    storage_type_id     INT          NOT NULL,
    storage_section_id  INT          NULL,
    zone_id             INT          NULL,
    capacity            INT          NOT NULL DEFAULT (1),
    is_active           BIT          NOT NULL DEFAULT (1),
    is_locked           BIT          NOT NULL DEFAULT (0),
    locked_by           INT          NULL,
    locked_at           DATETIME2(3) NULL,
    locked_reason       NVARCHAR(255) NULL,
    notes               NVARCHAR(255) NULL,
    created_at          DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by          INT NULL,
    updated_at          DATETIME2(3) NULL,
    updated_by          INT NULL,
    CONSTRAINT uq_bins_code        UNIQUE (bin_code),
    CONSTRAINT fk_bins_storage_type
        FOREIGN KEY (storage_type_id)  REFERENCES locations.storage_types(storage_type_id),
    CONSTRAINT fk_bins_storage_section
        FOREIGN KEY (storage_section_id) REFERENCES locations.storage_sections(storage_section_id),
    CONSTRAINT fk_bins_zone
        FOREIGN KEY (zone_id) REFERENCES locations.zones(zone_id)
);

CREATE INDEX IX_bins_storage_lookup
ON locations.bins (storage_type_id, storage_section_id, zone_id)
INCLUDE (capacity, is_active);

/* ============================================================
   locations.bin_reservations
   ------------------------------------------------------------
   Temporary claims on bins for putaway / movement planning.
   ============================================================ */
CREATE TABLE locations.bin_reservations
(
    reservation_id   INT IDENTITY(1,1) PRIMARY KEY,

    bin_id           INT NOT NULL,

    reservation_type NVARCHAR(50) NOT NULL, -- PUTAWAY, MOVE, PICK

    reserved_by      INT NOT NULL,
    reserved_at      DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    expires_at       DATETIME2(3) NOT NULL,

    CONSTRAINT fk_bin_reservations_bin
        FOREIGN KEY (bin_id)
        REFERENCES locations.bins(bin_id)
);

CREATE INDEX IX_bin_reservations_bin_expiry
ON locations.bin_reservations (bin_id, expires_at);

/* ============================================================
   inventory.skus
   ------------------------------------------------------------
   Canonical product master.
   Defines physical characteristics and storage intent.
   ============================================================ */
GO


-- -----------------------------------------------------------------------------
-- 050_locations\040_usp_lock_unlock_bin.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE locations.usp_lock_bin
(
    @bin_code       NVARCHAR(100),
    @reason         NVARCHAR(255)    = NULL,
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code;
            ROLLBACK; RETURN;
        END

        DECLARE @bin_id INT;

        SELECT @bin_id = bin_id
        FROM locations.bins WITH (UPDLOCK, HOLDLOCK)
        WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS;

        IF @bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF EXISTS (SELECT 1 FROM locations.bins WHERE bin_id = @bin_id AND is_locked = 1)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN02' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE locations.bins
        SET is_locked     = 1,
            locked_by     = @user_id,
            locked_at     = SYSUTCDATETIME(),
            locked_reason = @reason,
            updated_at    = SYSUTCDATETIME(),
            updated_by    = @user_id
        WHERE bin_id = @bin_id;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN01' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code;
    END CATCH
END;
GO

CREATE OR ALTER PROCEDURE locations.usp_unlock_bin
(
    @bin_code       NVARCHAR(100),
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code;
            ROLLBACK; RETURN;
        END

        DECLARE @bin_id INT;

        SELECT @bin_id = bin_id
        FROM locations.bins WITH (UPDLOCK, HOLDLOCK)
        WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS;

        IF @bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF EXISTS (SELECT 1 FROM locations.bins WHERE bin_id = @bin_id AND is_locked = 0)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN03' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE locations.bins
        SET is_locked     = 0,
            locked_by     = NULL,
            locked_at     = NULL,
            locked_reason = NULL,
            updated_at    = SYSUTCDATETIME(),
            updated_by    = @user_id
        WHERE bin_id = @bin_id;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 050_locations\050_usp_create_bins.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

-- ============================================================
-- Single bin creation
-- ============================================================

CREATE OR ALTER PROCEDURE locations.usp_create_bin
(
    @bin_code          NVARCHAR(100),
    @storage_type_code NVARCHAR(50),
    @zone_code         NVARCHAR(50)     = NULL,
    @section_code      NVARCHAR(50)     = NULL,
    @capacity          INT              = 1,
    @notes             NVARCHAR(255)    = NULL,
    @user_id           INT              = NULL,
    @session_id        UNIQUEIDENTIFIER = NULL,
    @correlation_id    UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code, 0 AS bin_id;
            ROLLBACK; RETURN;
        END

        -- Validate bin code unique
        IF EXISTS (SELECT 1 FROM locations.bins WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN04' AS result_code, 0 AS bin_id;
            ROLLBACK; RETURN;
        END

        DECLARE @storage_type_id INT =
            (SELECT storage_type_id FROM locations.storage_types
             WHERE storage_type_code = @storage_type_code COLLATE Latin1_General_CS_AS);

        IF @storage_type_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN05' AS result_code, 0 AS bin_id;
            ROLLBACK; RETURN;
        END

        DECLARE @zone_id INT =
            (SELECT zone_id FROM locations.zones
             WHERE zone_code = @zone_code COLLATE Latin1_General_CS_AS);

        DECLARE @section_id INT =
            (SELECT storage_section_id FROM locations.storage_sections
             WHERE section_code = @section_code COLLATE Latin1_General_CS_AS);

        DECLARE @new_bin_id INT;

        INSERT INTO locations.bins
            (bin_code, storage_type_id, zone_id, storage_section_id, capacity, notes, created_by, is_active)
        VALUES
            (@bin_code, @storage_type_id, @zone_id, @section_id, @capacity, @notes, @user_id, 0);

        SET @new_bin_id = SCOPE_IDENTITY();

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN03' AS result_code, @new_bin_id AS bin_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code, 0 AS bin_id;
    END CATCH
END;
GO

-- ============================================================
-- Bulk bin creation — generates a range from a template
--
-- Example: prefix='R', rows=1-10, cols=A-D, depth=1-2
--   generates: R0101A1, R0101A2, R0101B1 ... R1004D2
--
-- Pattern: {prefix}{row:2}{col}{depth}
-- All params optional — depth defaults to 1 slot per position
-- ============================================================

CREATE OR ALTER PROCEDURE locations.usp_create_bins_bulk
(
    @prefix            NVARCHAR(10),
    @storage_type_code NVARCHAR(50),
    @row_from          INT,
    @row_to            INT,
    @col_from          CHAR(1)          = 'A',
    @col_to            CHAR(1)          = 'A',
    @depth_from        INT              = 1,
    @depth_to          INT              = 1,
    @zone_code         NVARCHAR(50)     = NULL,
    @section_code      NVARCHAR(50)     = NULL,
    @capacity          INT              = 1,
    @user_id           INT              = NULL,
    @session_id        UNIQUEIDENTIFIER = NULL,
    @correlation_id    UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code, 0 AS created_count, 0 AS skipped_count;
            ROLLBACK; RETURN;
        END

        DECLARE @storage_type_id INT =
            (SELECT storage_type_id FROM locations.storage_types
             WHERE storage_type_code = @storage_type_code COLLATE Latin1_General_CS_AS);

        IF @storage_type_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN05' AS result_code, 0 AS created_count;
            ROLLBACK; RETURN;
        END

        DECLARE @zone_id INT =
            (SELECT zone_id FROM locations.zones
             WHERE zone_code = @zone_code COLLATE Latin1_General_CS_AS);

        DECLARE @section_id INT =
            (SELECT storage_section_id FROM locations.storage_sections
             WHERE section_code = @section_code COLLATE Latin1_General_CS_AS);

        DECLARE @row     INT = @row_from;
        DECLARE @col_ord INT = ASCII(@col_from);
        DECLARE @depth   INT;
        DECLARE @bin_code NVARCHAR(100);
        DECLARE @created INT = 0;
        DECLARE @skipped INT = 0;

        WHILE @row <= @row_to
        BEGIN
            SET @col_ord = ASCII(@col_from);
            WHILE @col_ord <= ASCII(@col_to)
            BEGIN
                SET @depth = @depth_from;
                WHILE @depth <= @depth_to
                BEGIN
                    SET @bin_code = @prefix
                        + RIGHT('0' + CAST(@row   AS NVARCHAR(2)), 2)
                        + RIGHT('0' + CAST(@depth AS NVARCHAR(2)), 2)
                        + CHAR(@col_ord);

                    IF NOT EXISTS (
                        SELECT 1 FROM locations.bins
                        WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS
                    )
                    BEGIN
                        INSERT INTO locations.bins
                            (bin_code, storage_type_id, zone_id, storage_section_id, capacity, created_by, is_active)
                        VALUES
                            (@bin_code, @storage_type_id, @zone_id, @section_id, @capacity, @user_id, 0);
                        SET @created = @created + 1;
                    END
                    ELSE
                        SET @skipped = @skipped + 1;

                    SET @depth = @depth + 1;
                END
                SET @col_ord = @col_ord + 1;
            END
            SET @row = @row + 1;
        END

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN04' AS result_code,
               @created AS created_count, @skipped AS skipped_count;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code, 0 AS created_count, 0 AS skipped_count;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 050_locations\060_usp_update_bin.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE locations.usp_update_bin
(
    @bin_code_current  NVARCHAR(100),       -- existing bin code (lookup key)
    @bin_code_new      NVARCHAR(100) = NULL, -- rename: only allowed when empty
    @storage_type_code NVARCHAR(50)  = NULL, -- only allowed when empty
    @zone_code         NVARCHAR(50)  = NULL, -- always allowed (pass NULL to clear)
    @section_code      NVARCHAR(50)  = NULL, -- always allowed (pass NULL to clear)
    @capacity          INT           = NULL, -- allowed, warned if below occupancy
    @notes             NVARCHAR(255) = NULL, -- always allowed
    @clear_notes       BIT           = 0,    -- explicit flag to clear notes
    @user_id           INT              = NULL,
    @session_id        UNIQUEIDENTIFIER = NULL,
    @correlation_id    UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code, CAST(0 AS BIT) AS capacity_warning;
            ROLLBACK; RETURN;
        END

        DECLARE @bin_id      INT;
        DECLARE @unit_count  INT;

        SELECT
            @bin_id     = bin_id,
            @unit_count = (
                SELECT COUNT(*)
                FROM inventory.inventory_placements ip
                JOIN inventory.inventory_units iu
                    ON iu.inventory_unit_id = ip.inventory_unit_id
                   AND iu.stock_state_code NOT IN ('SHP', 'REV')
                WHERE ip.bin_id = b.bin_id
            )
        FROM locations.bins b WITH (UPDLOCK, HOLDLOCK)
        WHERE b.bin_code = @bin_code_current COLLATE Latin1_General_CS_AS;

        IF @bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN01' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Rename: only when empty
        IF @bin_code_new IS NOT NULL AND @bin_code_new <> @bin_code_current
        BEGIN
            IF @unit_count > 0
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRBIN06' AS result_code;
                ROLLBACK; RETURN;
            END
            IF EXISTS (
                SELECT 1 FROM locations.bins
                WHERE bin_code = @bin_code_new COLLATE Latin1_General_CS_AS
                  AND bin_id  <> @bin_id
            )
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRBIN04' AS result_code;
                ROLLBACK; RETURN;
            END
        END

        -- Storage type change: only when empty
        DECLARE @storage_type_id INT = NULL;
        IF @storage_type_code IS NOT NULL
        BEGIN
            IF @unit_count > 0
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRBIN07' AS result_code;
                ROLLBACK; RETURN;
            END
            SET @storage_type_id =
                (SELECT storage_type_id FROM locations.storage_types
                 WHERE storage_type_code = @storage_type_code COLLATE Latin1_General_CS_AS);
            IF @storage_type_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRBIN05' AS result_code;
                ROLLBACK; RETURN;
            END
        END

        -- Capacity: warn if below occupancy but allow
        DECLARE @warn_capacity BIT = 0;
        IF @capacity IS NOT NULL AND @capacity < @unit_count
            SET @warn_capacity = 1;

        -- Resolve zone and section IDs
        DECLARE @zone_id    INT = NULL;
        DECLARE @section_id INT = NULL;

        IF @zone_code IS NOT NULL
            SET @zone_id = (SELECT zone_id FROM locations.zones WHERE zone_code = @zone_code COLLATE Latin1_General_CS_AS);

        IF @section_code IS NOT NULL
            SET @section_id = (SELECT storage_section_id FROM locations.storage_sections WHERE section_code = @section_code COLLATE Latin1_General_CS_AS);

        -- Apply updates (only fields explicitly provided)
        UPDATE locations.bins
        SET
            bin_code           = ISNULL(@bin_code_new,      bin_code),
            storage_type_id    = ISNULL(@storage_type_id,   storage_type_id),
            zone_id            = CASE WHEN @zone_code    IS NOT NULL THEN @zone_id    ELSE zone_id    END,
            storage_section_id = CASE WHEN @section_code IS NOT NULL THEN @section_id ELSE storage_section_id END,
            capacity           = ISNULL(@capacity,          capacity),
            notes              = CASE
                                    WHEN @clear_notes = 1 THEN NULL
                                    WHEN @notes IS NOT NULL THEN @notes
                                    ELSE notes
                                 END,
            updated_at         = SYSUTCDATETIME(),
            updated_by         = @user_id
        WHERE bin_id = @bin_id;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN05' AS result_code,
               @warn_capacity AS capacity_warning;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code, CAST(0 AS BIT) AS capacity_warning;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 050_locations\070_usp_deactivate_reactivate_bin.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

-- ============================================================
-- Deactivate bin (soft delete)
-- Blocked if: has active stock OR open warehouse tasks
-- ============================================================

CREATE OR ALTER PROCEDURE locations.usp_deactivate_bin
(
    @bin_code       NVARCHAR(100),
    @reason         NVARCHAR(255)    = NULL,
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code;
            ROLLBACK; RETURN;
        END

        DECLARE @bin_id INT;

        SELECT @bin_id = bin_id
        FROM locations.bins WITH (UPDLOCK, HOLDLOCK)
        WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS;

        IF @bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF EXISTS (SELECT 1 FROM locations.bins WHERE bin_id = @bin_id AND is_active = 0)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN08' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Block if stock present
        IF EXISTS (
            SELECT 1
            FROM inventory.inventory_placements ip
            JOIN inventory.inventory_units iu
                ON iu.inventory_unit_id = ip.inventory_unit_id
               AND iu.stock_state_code NOT IN ('SHP', 'REV')
            WHERE ip.bin_id = @bin_id
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN09' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Block if open warehouse tasks assigned to this bin
        IF EXISTS (
            SELECT 1
            FROM warehouse.warehouse_tasks
            WHERE (source_bin_id = @bin_id OR destination_bin_id = @bin_id)
              AND task_state_code NOT IN ('CNF', 'CNL', 'EXP')
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN10' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE locations.bins
        SET is_active  = 0,
            notes      = CASE
                            WHEN @reason IS NOT NULL
                            THEN ISNULL(notes + ' | ', '') + 'Deactivated: ' + @reason
                            ELSE notes
                         END,
            updated_at = SYSUTCDATETIME(),
            updated_by = @user_id
        WHERE bin_id = @bin_id;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN06' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code;
    END CATCH
END;
GO

-- ============================================================
-- Reactivate bin
-- ============================================================

CREATE OR ALTER PROCEDURE locations.usp_reactivate_bin
(
    @bin_code       NVARCHAR(100),
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL,
    @correlation_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF auth.fn_has_permission(@user_id, 'bins.manage') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code;
            ROLLBACK; RETURN;
        END

        DECLARE @bin_id INT;

        SELECT @bin_id = bin_id
        FROM locations.bins WITH (UPDLOCK, HOLDLOCK)
        WHERE bin_code = @bin_code COLLATE Latin1_General_CS_AS;

        IF @bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF EXISTS (SELECT 1 FROM locations.bins WHERE bin_id = @bin_id AND is_active = 1)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRBIN11' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE locations.bins
        SET is_active  = 1,
            updated_at = SYSUTCDATETIME(),
            updated_by = @user_id
        WHERE bin_id = @bin_id;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCBIN07' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRBIN99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 050_locations\080_zones_sections_setup.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

-- updated_at/updated_by are now part of 010_tables.sql for both zones and storage_sections.
-- This file creates the summary views that depend on those columns.

-- ============================================================
-- v_zones — zones with bin count
-- ============================================================
CREATE OR ALTER VIEW locations.v_zones
AS
SELECT
    z.zone_id,
    z.zone_code,
    z.zone_name,
    z.description,
    z.is_active,
    z.created_at,
    cb.username                          AS created_by_username,
    z.updated_at,
    ub.username                          AS updated_by_username,
    COUNT(b.bin_id)                      AS total_bins,
    SUM(CASE WHEN b.is_active = 1 THEN 1 ELSE 0 END) AS active_bins
FROM locations.zones z
LEFT JOIN auth.users cb ON cb.id = z.created_by
LEFT JOIN auth.users ub ON ub.id = z.updated_by
LEFT JOIN locations.bins b ON b.zone_id = z.zone_id
GROUP BY
    z.zone_id, z.zone_code, z.zone_name, z.description,
    z.is_active, z.created_at, cb.username, z.updated_at, ub.username;
GO

-- ============================================================
-- v_sections — sections with bin count
-- ============================================================
CREATE OR ALTER VIEW locations.v_sections
AS
SELECT
    s.storage_section_id,
    s.section_code,
    s.section_name,
    s.description,
    s.is_active,
    s.created_at,
    cb.username                          AS created_by_username,
    s.updated_at,
    ub.username                          AS updated_by_username,
    COUNT(b.bin_id)                      AS total_bins,
    SUM(CASE WHEN b.is_active = 1 THEN 1 ELSE 0 END) AS active_bins
FROM locations.storage_sections s
LEFT JOIN auth.users cb ON cb.id = s.created_by
LEFT JOIN auth.users ub ON ub.id = s.updated_by
LEFT JOIN locations.bins b ON b.storage_section_id = s.storage_section_id
GROUP BY
    s.storage_section_id, s.section_code, s.section_name, s.description,
    s.is_active, s.created_at, cb.username, s.updated_at, ub.username;
GO
PRINT 'v_zones and v_sections created.';
GO


