-- -----------------------------------------------------------------------------
-- 060_inventory\usp_create_sku.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inventory.usp_create_sku
(
    @sku_code                       NVARCHAR(50),
    @sku_description                NVARCHAR(200),
    @ean                            NVARCHAR(50)     = NULL,
    @uom_code                       NVARCHAR(20)     = N'Each',
    @weight_per_unit                DECIMAL(10,3)    = NULL,
    @standard_hu_quantity           INT              = 0,
    @is_hazardous                   BIT              = 0,
    @is_batch_required              BIT              = 0,
    @is_full_hu_required            BIT              = 0,
    @preferred_storage_type_code    NVARCHAR(50)     = NULL,
    @preferred_storage_section_code NVARCHAR(50)     = NULL,
    @owner_party_code               NVARCHAR(50)     = NULL,
    @user_id                        INT              = NULL,
    @session_id                     UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF EXISTS (SELECT 1 FROM inventory.skus WHERE sku_code = @sku_code)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSKU02' AS result_code, NULL AS sku_id;
            ROLLBACK;
            RETURN;
        END

        -- Resolve storage type: use supplied code, fallback to RACK, fallback to any active
        DECLARE @storage_type_id INT =
            ISNULL(
                (SELECT TOP 1 storage_type_id FROM locations.storage_types WHERE storage_type_code = @preferred_storage_type_code AND is_active = 1),
                ISNULL(
                    (SELECT TOP 1 storage_type_id FROM locations.storage_types WHERE storage_type_code = 'RACK' AND is_active = 1),
                    (SELECT TOP 1 storage_type_id FROM locations.storage_types WHERE is_active = 1 ORDER BY storage_type_id)
                )
            );

        -- Resolve storage section: use supplied code, NULL if not found
        DECLARE @storage_section_id INT =
            (SELECT TOP 1 storage_section_id FROM locations.storage_sections WHERE section_code = @preferred_storage_section_code AND is_active = 1);

        -- Resolve owner party
        DECLARE @enable_multi_owner  BIT          = 0;
        DECLARE @default_owner_code  NVARCHAR(50) = NULL;
        DECLARE @owner_party_id      INT          = NULL;

        SELECT @enable_multi_owner = TRY_CAST(setting_value AS BIT)
        FROM operations.settings WHERE setting_name = 'inventory.enable_multi_owner';

        SELECT @default_owner_code = setting_value
        FROM operations.settings WHERE setting_name = 'inventory.default_owner_party_code';

        IF @owner_party_code IS NOT NULL
        BEGIN
            SET @owner_party_id = (SELECT party_id FROM core.parties WHERE party_code = @owner_party_code COLLATE Latin1_General_CS_AS AND is_active = 1);
            IF @owner_party_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRSKU03' AS result_code, NULL AS sku_id;
                ROLLBACK; RETURN;
            END
        END
        ELSE IF @enable_multi_owner = 0
        BEGIN
            -- Multi-owner disabled: silently assign default owner
            SET @owner_party_id = (SELECT party_id FROM core.parties WHERE party_code = @default_owner_code COLLATE Latin1_General_CS_AS AND is_active = 1);
        END
        ELSE
        BEGIN
            -- Multi-owner enabled but no owner provided: require it
            SELECT CAST(0 AS BIT) AS success, N'ERRSKU04' AS result_code, NULL AS sku_id;
            ROLLBACK; RETURN;
        END

        INSERT INTO inventory.skus
            (sku_code, sku_description, ean, uom_code, weight_per_unit,
             standard_hu_quantity, is_hazardous, is_batch_required, is_full_hu_required,
             is_active, owner_party_id,
             preferred_storage_type_id, preferred_storage_section_id,
             created_at, created_by)
        VALUES
            (@sku_code, @sku_description, @ean, @uom_code, @weight_per_unit,
             @standard_hu_quantity, @is_hazardous, @is_batch_required, @is_full_hu_required,
             1, @owner_party_id,
             @storage_type_id, @storage_section_id,
             SYSUTCDATETIME(), @user_id);

        DECLARE @sku_id INT = SCOPE_IDENTITY();

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCSKU01' AS result_code, @sku_id AS sku_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRSKU99' AS result_code, NULL AS sku_id;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 060_inventory\usp_update_sku.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inventory.usp_update_sku
(
    @sku_code                       NVARCHAR(50),
    @sku_description                NVARCHAR(200),
    @ean                            NVARCHAR(50)     = NULL,
    @uom_code                       NVARCHAR(20)     = N'Each',
    @weight_per_unit                DECIMAL(10,3)    = NULL,
    @standard_hu_quantity           INT              = 0,
    @is_hazardous                   BIT              = 0,
    @is_batch_required              BIT              = 0,
    @is_full_hu_required            BIT              = 0,
    @is_active                      BIT              = 1,
    @preferred_storage_type_code    NVARCHAR(50)     = NULL,
    @preferred_storage_section_code NVARCHAR(50)     = NULL,
    @owner_party_code               NVARCHAR(50)     = NULL,
    @user_id                        INT              = NULL,
    @session_id                     UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        IF NOT EXISTS (SELECT 1 FROM inventory.skus WHERE sku_code = @sku_code)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSKU01' AS result_code;
            ROLLBACK;
            RETURN;
        END

        -- Resolve storage type: use supplied code, keep existing if NULL supplied
        DECLARE @storage_type_id INT =
            CASE
                WHEN @preferred_storage_type_code IS NOT NULL
                THEN (SELECT TOP 1 storage_type_id FROM locations.storage_types WHERE storage_type_code = @preferred_storage_type_code AND is_active = 1)
                ELSE (SELECT preferred_storage_type_id FROM inventory.skus WHERE sku_code = @sku_code)
            END;

        -- Resolve storage section: use supplied code, keep existing if NULL supplied
        DECLARE @storage_section_id INT =
            CASE
                WHEN @preferred_storage_section_code IS NOT NULL
                THEN (SELECT TOP 1 storage_section_id FROM locations.storage_sections WHERE section_code = @preferred_storage_section_code AND is_active = 1)
                ELSE (SELECT preferred_storage_section_id FROM inventory.skus WHERE sku_code = @sku_code)
            END;

        -- Resolve owner: if provided, validate and use; otherwise keep existing
        DECLARE @owner_party_id INT = NULL;
        IF @owner_party_code IS NOT NULL
        BEGIN
            SET @owner_party_id = (SELECT party_id FROM core.parties WHERE party_code = @owner_party_code COLLATE Latin1_General_CS_AS AND is_active = 1);
            IF @owner_party_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRSKU03' AS result_code;
                ROLLBACK; RETURN;
            END
        END
        ELSE
        BEGIN
            -- Keep existing owner
            SELECT @owner_party_id = owner_party_id FROM inventory.skus WHERE sku_code = @sku_code;
        END

        UPDATE inventory.skus
        SET sku_description              = @sku_description,
            ean                          = @ean,
            uom_code                     = @uom_code,
            weight_per_unit              = @weight_per_unit,
            standard_hu_quantity         = @standard_hu_quantity,
            is_hazardous                 = @is_hazardous,
            is_batch_required            = @is_batch_required,
            is_full_hu_required          = @is_full_hu_required,
            is_active                    = @is_active,
            preferred_storage_type_id    = @storage_type_id,
            preferred_storage_section_id = @storage_section_id,
            owner_party_id               = @owner_party_id,
            updated_at                   = SYSUTCDATETIME(),
            updated_by                   = @user_id
        WHERE sku_code = @sku_code;

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCSKU02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRSKU99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 060_inventory\usp_update_stock_status.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inventory.usp_update_stock_status
(
    @sscc_list   NVARCHAR(MAX),
    @new_status  VARCHAR(2),
    @reason      NVARCHAR(200)    = NULL,
    @user_id     INT              = NULL,
    @session_id  UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    BEGIN TRY
        BEGIN TRAN;

        -- Permission check (Phase 2c)
        IF auth.fn_has_permission(@user_id, 'stock.status_change') = 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRPERM01' AS result_code, 0 AS affected_count;
            ROLLBACK; RETURN;
        END

        -- Validate target status exists
        IF NOT EXISTS (SELECT 1 FROM inventory.stock_statuses WHERE status_code = @new_status)
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINV02' AS result_code, 0 AS affected_count;
            ROLLBACK; RETURN;
        END

        -- Parse comma-separated SSCC list into a table
        DECLARE @ssccs TABLE (sscc NVARCHAR(100));

        INSERT INTO @ssccs (sscc)
        SELECT LTRIM(RTRIM(value))
        FROM STRING_SPLIT(@sscc_list, ',')
        WHERE LTRIM(RTRIM(value)) <> '';

        DECLARE @now          DATETIME2(3) = SYSUTCDATETIME();
        DECLARE @affected_count INT = 0;

        -- Update matching active units
        UPDATE inventory.inventory_units
        SET stock_status_code = @new_status,
            updated_at        = @now,
            updated_by        = @user_id
        WHERE external_ref      IN (SELECT sscc FROM @ssccs)
          AND stock_state_code NOT IN ('REV', 'SHP');

        SET @affected_count = @@ROWCOUNT;

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCINV01' AS result_code, @affected_count AS affected_count;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRINV99' AS result_code, 0 AS affected_count;
    END CATCH
END;
GO
PRINT 'inventory.usp_update_stock_status created.';
GO


-- -----------------------------------------------------------------------------
-- 060_inventory\v_skus.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW inventory.v_skus
AS
SELECT
    s.sku_id,
    s.sku_code,
    s.sku_description,
    s.ean,
    s.uom_code,
    s.weight_per_unit,
    s.standard_hu_quantity,
    s.is_hazardous,
    s.is_batch_required,
    s.is_full_hu_required,
    s.is_active,
    st.storage_type_code        AS preferred_storage_type_code,
    ss.section_code             AS preferred_section_code,
    s.created_at,
    cu.username                 AS created_by_username,
    s.updated_at,
    uu.username                 AS updated_by_username,
    s.owner_party_id,
    op.party_code               AS owner_party_code,
    op.display_name             AS owner_name
FROM inventory.skus s
LEFT JOIN locations.storage_types    st ON st.storage_type_id    = s.preferred_storage_type_id
LEFT JOIN locations.storage_sections ss ON ss.storage_section_id = s.preferred_storage_section_id
LEFT JOIN auth.users cu              ON cu.id = s.created_by
LEFT JOIN auth.users uu              ON uu.id = s.updated_by
LEFT JOIN core.parties op            ON op.party_id = s.owner_party_id;
GO
PRINT 'inventory.v_skus created.';
GO


