-- -----------------------------------------------------------------------------
-- 070_inbound\usp_activate_inbound.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inbound.usp_activate_inbound
(
    @inbound_id INT,
    @user_id INT = NULL,
    @session_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE
        @current_status      VARCHAR(3),
        @existing_mode       VARCHAR(6),
        @sscc_line_count     INT,
        @manual_line_count   INT,
        @mode_code           VARCHAR(6);

    BEGIN TRY
        BEGIN TRAN;

        SELECT
            @current_status = inbound_status_code,
            @existing_mode  = inbound_mode_code
        FROM inbound.inbound_deliveries WITH (UPDLOCK, HOLDLOCK)
        WHERE inbound_id = @inbound_id;

        IF @current_status IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB01' AS result_code, NULL AS inbound_id;
            ROLLBACK;
            RETURN;
        END

        IF NOT EXISTS
        (
            SELECT 1
            FROM inbound.inbound_status_transitions
            WHERE from_status_code = @current_status
              AND to_status_code   = 'ACT'
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB05' AS result_code, NULL AS inbound_id;
            ROLLBACK;
            RETURN;
        END

        IF NOT EXISTS
        (
            SELECT 1
            FROM inbound.inbound_lines
            WHERE inbound_id = @inbound_id
              AND line_state_code <> 'CNL'
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB03' AS result_code, NULL AS inbound_id;
            ROLLBACK;
            RETURN;
        END

        SELECT
            @sscc_line_count = COUNT(DISTINCT l.inbound_line_id)
        FROM inbound.inbound_lines l
        JOIN inbound.inbound_expected_units eu
            ON eu.inbound_line_id = l.inbound_line_id
        WHERE l.inbound_id = @inbound_id
          AND l.line_state_code <> 'CNL';

        SELECT
            @manual_line_count = COUNT(*)
        FROM inbound.inbound_lines l
        WHERE l.inbound_id = @inbound_id
          AND l.line_state_code <> 'CNL'
          AND NOT EXISTS (
                SELECT 1
                FROM inbound.inbound_expected_units eu
                WHERE eu.inbound_line_id = l.inbound_line_id
          );

        IF @sscc_line_count > 0 AND @manual_line_count > 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINBHYB01' AS result_code, NULL AS inbound_id;
            ROLLBACK;
            RETURN;
        END

        IF @sscc_line_count > 0
            SET @mode_code = 'SSCC';
        ELSE
            SET @mode_code = 'MANUAL';

        IF @existing_mode IS NOT NULL AND @existing_mode <> @mode_code
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINBMODE01' AS result_code, NULL AS inbound_id;
            ROLLBACK;
            RETURN;
        END

        EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
        EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

        UPDATE inbound.inbound_deliveries
        SET inbound_status_code = 'ACT',
            inbound_mode_code   = @mode_code,
            updated_at          = SYSUTCDATETIME(),
            updated_by          = @user_id
        WHERE inbound_id = @inbound_id;

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCINB01' AS result_code, @inbound_id AS inbound_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRINB99' AS result_code, NULL AS inbound_id;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 070_inbound\usp_cancel_inbound.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inbound.usp_cancel_inbound
(
    @inbound_ref    NVARCHAR(50),
    @reason         NVARCHAR(200)    = NULL,
    @user_id        INT              = NULL,
    @session_id     UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        DECLARE @inbound_id    INT;
        DECLARE @status_code   VARCHAR(3);

        SELECT
            @inbound_id  = inbound_id,
            @status_code = inbound_status_code
        FROM inbound.inbound_deliveries WITH (UPDLOCK, HOLDLOCK)
        WHERE inbound_ref = @inbound_ref COLLATE Latin1_General_CS_AS;

        -- Not found
        IF @inbound_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB03' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Already terminal
        IF @status_code IN ('CLS', 'CNL')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB04' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Partially or fully received — cannot cancel
        IF @status_code = 'RCV'
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB05' AS result_code;
            ROLLBACK; RETURN;
        END

        -- ACT status: block if any receipts exist
        IF @status_code = 'ACT'
        BEGIN
            IF EXISTS (
                SELECT 1
                FROM inbound.inbound_receipts r
                JOIN inbound.inbound_lines l ON l.inbound_line_id = r.inbound_line_id
                WHERE l.inbound_id = @inbound_id
                  AND r.is_reversal = 0
            )
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRINB06' AS result_code;
                ROLLBACK; RETURN;
            END
        END

        -- Cancel the delivery header
        UPDATE inbound.inbound_deliveries
        SET inbound_status_code = 'CNL',
            updated_at          = SYSUTCDATETIME(),
            updated_by          = @user_id
        WHERE inbound_id = @inbound_id;

        -- Cancel all open lines
        UPDATE inbound.inbound_lines
        SET line_state_code = 'CNL',
            updated_at      = SYSUTCDATETIME()
        WHERE inbound_id      = @inbound_id
          AND line_state_code NOT IN ('RCV', 'CNL');

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCINB03' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRINB99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 070_inbound\usp_create_expected_unit.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE inbound.usp_create_expected_unit
(
    @inbound_ref      NVARCHAR(50),
    @sscc             NVARCHAR(18),
    @quantity         INT,
    @batch_number     NVARCHAR(100)    = NULL,
    @best_before_date DATE             = NULL,
    @sku_code         NVARCHAR(50)     = NULL,   -- optional: target a specific line by SKU
    @user_id          INT              = NULL,
    @session_id       UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        -- Resolve line: prefer @sku_code match, fall back to most recent line
        DECLARE @inbound_line_id INT =
            CASE
                WHEN @sku_code IS NOT NULL THEN (
                    SELECT TOP 1 l.inbound_line_id
                    FROM inbound.inbound_lines l
                    JOIN inbound.inbound_deliveries d ON d.inbound_id = l.inbound_id
                    JOIN inventory.skus sk ON sk.sku_id = l.sku_id
                    WHERE d.inbound_ref = @inbound_ref
                      AND sk.sku_code  = @sku_code
                    ORDER BY l.line_no DESC
                )
                ELSE (
                    SELECT TOP 1 l.inbound_line_id
                    FROM inbound.inbound_lines l
                    JOIN inbound.inbound_deliveries d ON d.inbound_id = l.inbound_id
                    WHERE d.inbound_ref = @inbound_ref
                    ORDER BY l.line_no DESC
                )
            END;

        IF @inbound_line_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINB01' AS result_code,
                   NULL AS inbound_expected_unit_id;
            ROLLBACK;
            RETURN;
        END

        -- Batch required guard: if SKU requires batch, reject pre-advice without one
        DECLARE @is_batch_required BIT;

        SELECT @is_batch_required = s.is_batch_required
        FROM inbound.inbound_lines l
        JOIN inventory.skus s ON s.sku_id = l.sku_id
        WHERE l.inbound_line_id = @inbound_line_id;

        IF @is_batch_required = 1
           AND NULLIF(LTRIM(RTRIM(ISNULL(@batch_number, N''))), N'') IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINBU02' AS result_code,
                   NULL AS inbound_expected_unit_id;
            ROLLBACK;
            RETURN;
        END

        -- Duplicate SSCC check within this inbound
        IF EXISTS (
            SELECT 1
            FROM inbound.inbound_expected_units eu
            JOIN inbound.inbound_lines l ON l.inbound_line_id = eu.inbound_line_id
            JOIN inbound.inbound_deliveries d ON d.inbound_id = l.inbound_id
            WHERE d.inbound_ref = @inbound_ref
              AND eu.expected_external_ref = @sscc
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRINBU01' AS result_code,
                   NULL AS inbound_expected_unit_id;
            ROLLBACK;
            RETURN;
        END

        INSERT INTO inbound.inbound_expected_units
            (inbound_line_id, expected_external_ref, expected_quantity,
             batch_number, best_before_date, created_at, created_by)
        VALUES
            (@inbound_line_id, @sscc, @quantity,
             @batch_number, @best_before_date, SYSUTCDATETIME(), @user_id);

        DECLARE @unit_id INT = SCOPE_IDENTITY();

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCINBU01' AS result_code,
               @unit_id AS inbound_expected_unit_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRINB99' AS result_code,
               NULL AS inbound_expected_unit_id;
    END CATCH
END;
GO
PRINT 'inbound.usp_create_expected_unit created.';
GO

