-- -----------------------------------------------------------------------------
-- 075_post_inbound\v_locations.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW locations.v_locations
AS
SELECT
    b.bin_id,
    b.bin_code,
    st.storage_type_code,
    st.storage_type_name,
    ss.section_code,
    z.zone_code,
    z.zone_name,
    b.capacity,
    b.is_active,
    b.is_locked,
    b.locked_reason,
    b.notes,
    b.locked_at,
    lb.username                                     AS locked_by_username,

    -- Stock summary
    COUNT(iu.inventory_unit_id)                     AS unit_count,
    ISNULL(SUM(iu.quantity), 0)                     AS total_qty,

    -- Single-unit convenience columns (NULL when multi-unit)
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(iu.external_ref)  END             AS sscc,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(sk.sku_code)      END             AS sku_code,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(sk.sku_description) END           AS sku_description,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(iu.batch_number)  END             AS batch_number,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(iu.best_before_date) END          AS best_before_date,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(iu.stock_state_code) END          AS stock_state,
    CASE WHEN COUNT(iu.inventory_unit_id) = 1
         THEN MAX(iu.stock_status_code) END         AS stock_status

FROM locations.bins b
JOIN locations.storage_types st      ON st.storage_type_id  = b.storage_type_id
LEFT JOIN locations.storage_sections ss ON ss.storage_section_id = b.storage_section_id
LEFT JOIN locations.zones z          ON z.zone_id           = b.zone_id
LEFT JOIN auth.users lb              ON lb.id               = b.locked_by

-- Active inventory placements only (one row per unit — PK guarantees single active placement)
LEFT JOIN inventory.inventory_placements ip
    ON ip.bin_id      = b.bin_id
LEFT JOIN inventory.inventory_units iu
    ON iu.inventory_unit_id = ip.inventory_unit_id
    AND iu.stock_state_code NOT IN ('SHP', 'REV')
LEFT JOIN inventory.skus sk
    ON sk.sku_id = iu.sku_id

GROUP BY
    b.bin_id, b.bin_code,
    st.storage_type_code, st.storage_type_name,
    ss.section_code,
    z.zone_code, z.zone_name,
    b.capacity, b.is_active, b.is_locked,
    b.locked_reason, b.notes, b.locked_at,
    lb.username;
GO
PRINT 'locations.v_locations created.';
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\010_tables.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE TABLE warehouse.warehouse_tasks
(
    task_id                 INT IDENTITY(1,1) PRIMARY KEY,

    -- Task classification
    task_type_code          NVARCHAR(20) NOT NULL,   -- PUTAWAY, MOVE, PICK

    -- Object being moved
    inventory_unit_id       INT NOT NULL,

    -- Movement context
    source_bin_id           INT NULL,
    destination_bin_id      INT NULL,

    -- Task lifecycle
    task_state_code         VARCHAR(3) NOT NULL DEFAULT 'OPN', -- OPN, CLM, CNF, CNL, EXP

    -- Assignment
    claimed_by_user_id      INT NULL,
    claimed_session_id      UNIQUEIDENTIFIER NULL,

    claimed_at              DATETIME2(3) NULL,
    expires_at              DATETIME2(3) NULL,

    -- Completion
    completed_at            DATETIME2(3) NULL,
    completed_by_user_id    INT NULL,

    -- Audit
    created_at              DATETIME2(3) NOT NULL DEFAULT SYSUTCDATETIME(),
    created_by              INT NULL,
    updated_at              DATETIME2(3) NULL,
    updated_by              INT NULL,

    CONSTRAINT fk_tasks_inventory_unit
        FOREIGN KEY (inventory_unit_id)
        REFERENCES inventory.inventory_units(inventory_unit_id),

    CONSTRAINT fk_tasks_source_bin
        FOREIGN KEY (source_bin_id)
        REFERENCES locations.bins(bin_id),

    CONSTRAINT fk_tasks_destination_bin
        FOREIGN KEY (destination_bin_id)
        REFERENCES locations.bins(bin_id)
);

CREATE INDEX IX_tasks_state
ON warehouse.warehouse_tasks (task_state_code);

CREATE INDEX IX_tasks_inventory
ON warehouse.warehouse_tasks (inventory_unit_id);

CREATE INDEX IX_tasks_expiry
ON warehouse.warehouse_tasks (expires_at);

/* ============================================================
   warehouse.task_states
   ------------------------------------------------------------
   Canonical lifecycle states for warehouse tasks.
   ============================================================ */
CREATE TABLE warehouse.task_states
(
    state_code      VARCHAR(3) NOT NULL PRIMARY KEY,
    state_desc      NVARCHAR(30) NOT NULL,
    is_terminal     BIT NOT NULL DEFAULT 0
);

INSERT INTO warehouse.task_states (state_code, state_desc, is_terminal)
VALUES
('OPN','OPEN',0),
('CLM','CLAIMED',0),
('CNF','CONFIRMED',1),
('EXP','EXPIRED',1),
('CNL','CANCELLED',1);

/* ============================================================
   warehouse.task_state_transitions
   ------------------------------------------------------------
   Defines legal transitions between task lifecycle states.
   ============================================================ */
CREATE TABLE warehouse.task_state_transitions
(
    from_state_code    VARCHAR(3) NOT NULL,
    to_state_code      VARCHAR(3) NOT NULL,
    requires_authority BIT NOT NULL DEFAULT 0,
    notes              NVARCHAR(200) NULL,

    PRIMARY KEY (from_state_code, to_state_code),

    FOREIGN KEY (from_state_code)
        REFERENCES warehouse.task_states(state_code),

    FOREIGN KEY (to_state_code)
        REFERENCES warehouse.task_states(state_code)
);

INSERT INTO warehouse.task_state_transitions
VALUES
('OPN','CLM',0,'Operator claims task'),
('OPN','CNL',1,'Task cancelled before claim'),

('CLM','CNF',0,'Task completed'),
('CLM','EXP',0,'Task expired due to TTL'),
('CLM','CNL',1,'Supervisor cancels task');

ALTER TABLE warehouse.warehouse_tasks
ADD CONSTRAINT fk_tasks_state
FOREIGN KEY (task_state_code)
REFERENCES warehouse.task_states(state_code);

CREATE UNIQUE INDEX UX_tasks_open_unit
ON warehouse.warehouse_tasks (inventory_unit_id)
WHERE task_state_code IN ('OPN','CLM');
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_bin_to_bin_move_confirm.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_bin_to_bin_move_confirm
(
    @task_id          INT,
    @scanned_bin_code NVARCHAR(100),
    @user_id          INT              = NULL,
    @session_id       UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        SET @scanned_bin_code = LTRIM(RTRIM(@scanned_bin_code)) COLLATE Latin1_General_CS_AS;

        DECLARE
            @inventory_unit_id  INT,
            @source_bin_id      INT,
            @destination_bin_id INT,
            @dest_bin_code      NVARCHAR(100),
            @task_state         VARCHAR(3),
            @sku_id             INT,
            @now                DATETIME2(3) = SYSUTCDATETIME();

        SELECT
            @inventory_unit_id  = inventory_unit_id,
            @source_bin_id      = source_bin_id,
            @destination_bin_id = destination_bin_id,
            @task_state         = task_state_code
        FROM warehouse.warehouse_tasks WITH (UPDLOCK, HOLDLOCK)
        WHERE task_id       = @task_id
          AND task_type_code = 'MOVE'
          AND task_state_code IN ('OPN', 'CLM');

        IF @inventory_unit_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRMOVE05' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Validate scanned bin against destination
        SELECT @dest_bin_code = bin_code
        FROM locations.bins
        WHERE bin_id = @destination_bin_id;

        IF @dest_bin_code IS NOT NULL
           AND LTRIM(RTRIM(@scanned_bin_code)) <> LTRIM(RTRIM(@dest_bin_code))
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRMOVE06' AS result_code;
            ROLLBACK; RETURN;
        END

        -- If no destination was set on the task, resolve the scanned bin
        IF @destination_bin_id IS NULL
        BEGIN
            SELECT @destination_bin_id = bin_id
            FROM locations.bins
            WHERE bin_code = @scanned_bin_code COLLATE Latin1_General_CS_AS AND is_active = 1;

            IF @destination_bin_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRMOVE04' AS result_code;
                ROLLBACK; RETURN;
            END

            SET @dest_bin_code = @scanned_bin_code COLLATE Latin1_General_CS_AS;
        END

        SELECT @sku_id = sku_id FROM inventory.inventory_units WHERE inventory_unit_id = @inventory_unit_id;

        -- Update placement
        UPDATE inventory.inventory_placements
        SET bin_id = @destination_bin_id
        WHERE inventory_unit_id = @inventory_unit_id;

        -- If the unit is RCD and is leaving a staging bin, transition to PTW.
        -- A bin-to-bin move out of staging = manual putaway, regardless of destination.
        IF EXISTS (
            SELECT 1
            FROM inventory.inventory_units iu
            JOIN locations.bins b ON b.bin_id = @source_bin_id
            JOIN locations.storage_types st ON st.storage_type_id = b.storage_type_id
            WHERE iu.inventory_unit_id = @inventory_unit_id
              AND iu.stock_state_code  = 'RCD'
              AND st.storage_type_code = 'STAGE'
        )
        BEGIN
            UPDATE inventory.inventory_units
            SET stock_state_code = 'PTW',
                updated_at       = @now,
                updated_by       = @user_id
            WHERE inventory_unit_id = @inventory_unit_id;
        END

        -- Record movement — capture actual from/to state (may differ if RCD->PTW transition occurred)
        DECLARE @movement_id  INT;
        DECLARE @from_state   VARCHAR(3);
        DECLARE @to_state     VARCHAR(3);

        SELECT @to_state = stock_state_code FROM inventory.inventory_units WHERE inventory_unit_id = @inventory_unit_id;

        SELECT @from_state =
            CASE
                WHEN @to_state = 'PTW' AND EXISTS (
                    SELECT 1 FROM locations.bins b
                    JOIN locations.storage_types st ON st.storage_type_id = b.storage_type_id
                    WHERE b.bin_id = @source_bin_id AND st.storage_type_code = 'STAGE'
                ) THEN 'RCD'
                ELSE @to_state
            END;

        INSERT INTO inventory.inventory_movements
            (inventory_unit_id, sku_id, moved_qty,
             from_bin_id, to_bin_id,
             from_state_code, to_state_code,
             from_status_code, to_status_code,
             movement_type, reference_type, reference_id,
             moved_at, moved_by_user_id, session_id)
        SELECT
            @inventory_unit_id, @sku_id, quantity,
            @source_bin_id, @destination_bin_id,
            @from_state, @to_state,
            stock_status_code, stock_status_code,
            'MOVE', 'TASK', @task_id,
            @now, @user_id, @session_id
        FROM inventory.inventory_units
        WHERE inventory_unit_id = @inventory_unit_id;

        -- Complete task
        UPDATE warehouse.warehouse_tasks
        SET task_state_code      = 'CNF',
            completed_at         = @now,
            completed_by_user_id = @user_id,
            updated_at           = @now,
            updated_by           = @user_id
        WHERE task_id = @task_id;

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCMOVE02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRMOVE99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_bin_to_bin_move_create.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_bin_to_bin_move_create
(
    @external_ref         NVARCHAR(100),
    @destination_bin_code NVARCHAR(100)    = NULL,
    @user_id              INT              = NULL,
    @session_id           UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        -- Normalise inputs
        SET @external_ref         = LTRIM(RTRIM(@external_ref));
        IF @destination_bin_code IS NOT NULL
            SET @destination_bin_code = LTRIM(RTRIM(@destination_bin_code)) COLLATE Latin1_General_CS_AS;

        -- Resolve inventory unit by SSCC
        DECLARE
            @inventory_unit_id  INT,
            @stock_state_code   VARCHAR(3),
            @source_bin_id      INT,
            @source_bin_code    NVARCHAR(100),
            @destination_bin_id INT,
            @task_id            INT,
            @ttl_seconds        INT,
            @expires_at         DATETIME2(3),
            @now                DATETIME2(3) = SYSUTCDATETIME();

        SELECT
            @inventory_unit_id = inventory_unit_id,
            @stock_state_code  = stock_state_code
        FROM inventory.inventory_units
        WHERE external_ref = @external_ref
          AND stock_state_code NOT IN ('REV', 'SHP');

        IF @inventory_unit_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRMOVE01' AS result_code,
                   NULL AS task_id, NULL AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS destination_bin_code;
            ROLLBACK; RETURN;
        END

        -- Unit must be in PUT, PTW or RCD state to be moved
        IF @stock_state_code NOT IN ('PUT', 'PTW', 'RCD')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRMOVE02' AS result_code,
                   NULL AS task_id, @inventory_unit_id AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS destination_bin_code;
            ROLLBACK; RETURN;
        END

        -- Resolve current placement
        SELECT @source_bin_id = bin_id
        FROM inventory.inventory_placements
        WHERE inventory_unit_id = @inventory_unit_id;

        IF @source_bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRMOVE03' AS result_code,
                   NULL AS task_id, @inventory_unit_id AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS destination_bin_code;
            ROLLBACK; RETURN;
        END

        SELECT @source_bin_code = bin_code FROM locations.bins WHERE bin_id = @source_bin_id;

        -- Resolve destination bin if provided
        IF @destination_bin_code IS NOT NULL
        BEGIN
            DECLARE @dest_bin_is_active BIT;

            SELECT @destination_bin_id = bin_id,
                   @dest_bin_is_active = is_active
            FROM locations.bins
            WHERE bin_code = @destination_bin_code COLLATE Latin1_General_CS_AS;

            IF @destination_bin_id IS NULL
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRMOVE04' AS result_code,
                       NULL AS task_id, @inventory_unit_id AS inventory_unit_id,
                       @source_bin_code AS source_bin_code, @destination_bin_code AS destination_bin_code;
                ROLLBACK; RETURN;
            END

            IF @dest_bin_is_active = 0
            BEGIN
                SELECT CAST(0 AS BIT) AS success, N'ERRMOVE07' AS result_code,
                       NULL AS task_id, @inventory_unit_id AS inventory_unit_id,
                       @source_bin_code AS source_bin_code, @destination_bin_code AS destination_bin_code;
                ROLLBACK; RETURN;
            END
        END

        -- Suggest destination if not provided
        IF @destination_bin_code IS NULL
        BEGIN
            EXEC locations.usp_suggest_putaway_bin
                @inventory_unit_id = @inventory_unit_id,
                @suggested_bin_id  = @destination_bin_id OUTPUT;

            IF @destination_bin_id IS NOT NULL
                SELECT @destination_bin_code = bin_code FROM locations.bins WHERE bin_id = @destination_bin_id;
        END

        -- Reuse existing open task if present
        SELECT TOP 1
            @task_id           = task_id,
            @destination_bin_id = destination_bin_id,
            @expires_at        = expires_at
        FROM warehouse.warehouse_tasks
        WHERE inventory_unit_id = @inventory_unit_id
          AND task_type_code    = 'MOVE'
          AND task_state_code  IN ('OPN', 'CLM')
        ORDER BY created_at DESC;

        IF @task_id IS NOT NULL
        BEGIN
            DECLARE @existing_dest_code NVARCHAR(100);
            SELECT @existing_dest_code = bin_code FROM locations.bins WHERE bin_id = @destination_bin_id;
            COMMIT;
            SELECT CAST(1 AS BIT) AS success, N'SUCMOVE01' AS result_code,
                   @task_id AS task_id, @inventory_unit_id AS inventory_unit_id,
                   @source_bin_code AS source_bin_code, @existing_dest_code AS destination_bin_code;
            RETURN;
        END

        -- TTL
        SELECT @ttl_seconds = TRY_CAST(setting_value AS INT)
        FROM operations.settings
        WHERE setting_name = 'warehouse.putaway_task_ttl_seconds';

        IF @ttl_seconds IS NULL OR @ttl_seconds <= 0
            SET @ttl_seconds = 300;

        SET @expires_at = DATEADD(SECOND, @ttl_seconds, @now);

        -- Create move task
        INSERT INTO warehouse.warehouse_tasks
            (task_type_code, inventory_unit_id, source_bin_id, destination_bin_id,
             task_state_code, expires_at,
             claimed_by_user_id, claimed_at,
             created_by)
        VALUES
            ('MOVE', @inventory_unit_id, @source_bin_id, @destination_bin_id,
             'OPN', @expires_at,
             @user_id, @now,
             @user_id);

        SET @task_id = SCOPE_IDENTITY();

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCMOVE01' AS result_code,
               @task_id AS task_id, @inventory_unit_id AS inventory_unit_id,
               @source_bin_code AS source_bin_code,
               @destination_bin_code AS destination_bin_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRMOVE99' AS result_code,
               NULL AS task_id, NULL AS inventory_unit_id,
               NULL AS source_bin_code, NULL AS destination_bin_code;
    END CATCH
END;
GO
PRINT 'warehouse.usp_bin_to_bin_move_create created.';
GO

-- ── warehouse.usp_bin_to_bin_move_confirm ────────────────────────────────────
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_cancel_task.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_cancel_task
(
    @task_id    INT,
    @reason     NVARCHAR(200) = NULL,
    @user_id    INT,
    @session_id UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    DECLARE
        @current_state  VARCHAR(3),
        @is_terminal    BIT,
        @task_type      NVARCHAR(20),
        @dest_bin_id    INT,
        @now            DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        SELECT
            @current_state = wt.task_state_code,
            @is_terminal   = ts.is_terminal,
            @task_type     = wt.task_type_code,
            @dest_bin_id   = wt.destination_bin_id
        FROM warehouse.warehouse_tasks wt WITH (UPDLOCK, HOLDLOCK)
        JOIN warehouse.task_states ts ON ts.state_code = wt.task_state_code
        WHERE wt.task_id = @task_id;

        IF @current_state IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK03' AS result_code;
            ROLLBACK; RETURN;
        END

        IF @is_terminal = 1
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK06' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Validate transition is allowed
        IF NOT EXISTS (
            SELECT 1 FROM warehouse.task_state_transitions
            WHERE from_state_code = @current_state
              AND to_state_code   = 'CNL'
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK07' AS result_code;
            ROLLBACK; RETURN;
        END

        UPDATE warehouse.warehouse_tasks
        SET task_state_code = 'CNL',
            updated_at      = @now,
            updated_by      = @user_id
        WHERE task_id = @task_id;

        -- A cancelled PUTAWAY task's destination-bin reservation (created in
        -- usp_putaway_create_task_for_unit) has no further purpose - release
        -- it now rather than leave the bin needlessly held for the rest of
        -- the TTL window.
        IF @task_type = 'PUTAWAY' AND @dest_bin_id IS NOT NULL
        BEGIN
            DELETE FROM locations.bin_reservations
            WHERE bin_id = @dest_bin_id AND reservation_type = 'PUTAWAY' AND expires_at >= @now;
        END

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCTASK03' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRTASK99' AS result_code;
    END CATCH
END;
GO
PRINT 'warehouse.usp_cancel_task created.';
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_create_putaway_task.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_create_putaway_task
(
    @inventory_unit_id INT, @user_id INT = NULL, @session_id UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    DECLARE @sku_id INT, @stock_state VARCHAR(3), @current_bin_id INT,
            @dest_bin_id INT, @ttl_seconds INT, @expires_at DATETIME2(3), @task_id INT;

    BEGIN TRY
        BEGIN TRAN;

        SELECT @sku_id = sku_id, @stock_state = stock_state_code
        FROM inventory.inventory_units WHERE inventory_unit_id = @inventory_unit_id;

        IF @sku_id IS NULL
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK01' AS result_code, NULL AS task_id, NULL AS destination_bin_id; ROLLBACK; RETURN; END

        IF @stock_state <> 'RCD'
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK02' AS result_code, NULL AS task_id, NULL AS destination_bin_id; ROLLBACK; RETURN; END

        SELECT @current_bin_id = bin_id FROM inventory.inventory_placements WHERE inventory_unit_id = @inventory_unit_id;

        IF @current_bin_id IS NULL
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK03' AS result_code, NULL AS task_id, NULL AS destination_bin_id; ROLLBACK; RETURN; END

        IF EXISTS (SELECT 1 FROM warehouse.warehouse_tasks WHERE inventory_unit_id = @inventory_unit_id AND task_state_code IN ('OPN','CLM'))
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK05' AS result_code, NULL AS task_id, NULL AS destination_bin_id; ROLLBACK; RETURN; END

        EXEC locations.usp_suggest_putaway_bin @inventory_unit_id = @inventory_unit_id, @suggested_bin_id = @dest_bin_id OUTPUT;

        IF @dest_bin_id IS NULL
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK04' AS result_code, NULL AS task_id, NULL AS destination_bin_id; ROLLBACK; RETURN; END

        SELECT @ttl_seconds = TRY_CONVERT(INT, setting_value) FROM operations.settings
        WHERE setting_name = 'warehouse.putaway_task_ttl_seconds';

        IF @ttl_seconds IS NULL OR @ttl_seconds <= 0 SET @ttl_seconds = 300;
        SET @expires_at = DATEADD(SECOND, @ttl_seconds, SYSUTCDATETIME());

        INSERT INTO warehouse.warehouse_tasks
            (task_type_code, inventory_unit_id, source_bin_id, destination_bin_id, task_state_code, expires_at, created_by)
        VALUES ('PUTAWAY', @inventory_unit_id, @current_bin_id, @dest_bin_id, 'OPN', @expires_at, @user_id);

        SET @task_id = SCOPE_IDENTITY();
        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCTASK01' AS result_code,
               @task_id AS task_id, @dest_bin_id AS destination_bin_id;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRTASK99' AS result_code, NULL AS task_id, NULL AS destination_bin_id;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_putaway_confirm_task.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_putaway_confirm_task
(
    @task_id          INT,
    @scanned_bin_code NVARCHAR(100),
    @user_id          INT,
    @session_id       UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE
        @inventory_unit_id   INT, @source_bin_id INT, @dest_bin_id INT,
        @dest_bin_code       NVARCHAR(100), @sku_id INT, @quantity INT,
        @task_state          VARCHAR(3), @scanned_bin_id INT,
        @bin_capacity        INT, @bin_active BIT,
        @current_placements  INT, @active_reservations INT,
        @current_status_code VARCHAR(2), @now DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        SELECT @inventory_unit_id = inventory_unit_id, @source_bin_id = source_bin_id,
               @dest_bin_id = destination_bin_id, @task_state = task_state_code
        FROM warehouse.warehouse_tasks WITH (UPDLOCK, HOLDLOCK) WHERE task_id = @task_id;

        IF @inventory_unit_id IS NULL
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK01' AS result_code; ROLLBACK; RETURN; END

        IF @task_state NOT IN ('OPN','CLM')
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK07' AS result_code; ROLLBACK; RETURN; END

        SELECT @dest_bin_code = bin_code FROM locations.bins WHERE bin_id = @dest_bin_id;

        IF LTRIM(RTRIM(@scanned_bin_code)) COLLATE Latin1_General_CS_AS <> LTRIM(RTRIM(@dest_bin_code)) COLLATE Latin1_General_CS_AS
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK08' AS result_code; ROLLBACK; RETURN; END

        -- Lock the destination bin itself before checking capacity - counting
        -- inventory.inventory_placements/locations.bin_reservations with
        -- HOLDLOCK does NOT prevent this race, since with zero prior rows
        -- there is nothing to lock (the classic phantom-insert problem).
        -- Locking the bin row instead serializes every concurrent confirm
        -- targeting it, matching the UPDLOCK/HOLDLOCK pattern already used
        -- for the task row above and for orders in usp_allocate_order.
        SELECT @scanned_bin_id = bin_id, @bin_capacity = capacity, @bin_active = is_active
        FROM locations.bins WITH (UPDLOCK, HOLDLOCK) WHERE bin_id = @dest_bin_id;

        IF @bin_active = 0
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK09' AS result_code; ROLLBACK; RETURN; END

        -- Release this task's own reservation on the destination bin BEFORE
        -- checking capacity. It was created (usp_putaway_create_task_for_unit)
        -- purely to hold the bin open until THIS confirmation happens - it is
        -- not a competing claim from someone else, so counting it against
        -- this same confirmation is wrong and would make it impossible to
        -- ever confirm into a capacity-1 bin. If the transaction rolls back
        -- for any other reason below, this delete rolls back with it, so
        -- nothing is lost on a genuine failure.
        DELETE FROM locations.bin_reservations
        WHERE bin_id = @dest_bin_id AND reservation_type = 'PUTAWAY' AND expires_at >= @now;

        SELECT @current_placements = COUNT(*) FROM inventory.inventory_placements WHERE bin_id = @dest_bin_id;
        SELECT @active_reservations = COUNT(*) FROM locations.bin_reservations
        WHERE bin_id = @dest_bin_id AND expires_at > @now;

        IF (@current_placements + @active_reservations) >= @bin_capacity
        BEGIN SELECT CAST(0 AS BIT) AS success, N'ERRTASK09' AS result_code; ROLLBACK; RETURN; END

        SELECT @sku_id = sku_id, @quantity = quantity, @current_status_code = stock_status_code
        FROM inventory.inventory_units WITH (UPDLOCK, HOLDLOCK) WHERE inventory_unit_id = @inventory_unit_id;

        UPDATE inventory.inventory_placements SET bin_id = @dest_bin_id, placed_at = @now, placed_by = @user_id
        WHERE inventory_unit_id = @inventory_unit_id;

        UPDATE inventory.inventory_units
        SET stock_state_code = 'PTW', updated_at = @now, updated_by = @user_id
        WHERE inventory_unit_id = @inventory_unit_id AND stock_state_code = 'RCD';

        UPDATE warehouse.warehouse_tasks
        SET task_state_code = 'CNF', completed_at = @now, completed_by_user_id = @user_id,
            updated_at = @now, updated_by = @user_id
        WHERE task_id = @task_id;

        INSERT INTO inventory.inventory_movements
            (inventory_unit_id, sku_id, moved_qty, from_bin_id, to_bin_id,
             from_state_code, to_state_code, from_status_code, to_status_code,
             movement_type, reference_type, reference_id, moved_at, moved_by_user_id, session_id)
        VALUES
            (@inventory_unit_id, @sku_id, @quantity, @source_bin_id, @dest_bin_id,
             'RCD', 'PTW', @current_status_code, @current_status_code,
             'PUTAWAY', 'TASK', @task_id, @now, @user_id, @session_id);

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCTASK02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRTASK99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 080_warehouse\usp_putaway_create_task_for_unit.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE warehouse.usp_putaway_create_task_for_unit
(
    @inventory_unit_id INT,
    @user_id           INT,
    @session_id        UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE
        @task_id            INT,
        @dest_bin_id        INT,
        @dest_bin_code      NVARCHAR(100),
        @source_bin_id      INT,
        @ttl_seconds        INT,
        @expires_at         DATETIME2(3),
        @sku_id             INT,
        @state_code         VARCHAR(3),
        @stock_status_code  VARCHAR(2),
        @source_bin_code    NVARCHAR(100),
        @zone_code          NVARCHAR(50);

    BEGIN TRY
        BEGIN TRAN;

        SELECT @sku_id = sku_id, @state_code = stock_state_code, @stock_status_code = stock_status_code
        FROM inventory.inventory_units WHERE inventory_unit_id = @inventory_unit_id;

        IF @sku_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK01' AS result_code,
                   NULL AS task_id, NULL AS destination_bin_code, NULL AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS stock_state_code, NULL AS stock_status_code,
                   NULL AS expires_at, NULL AS zone_code;
            ROLLBACK; RETURN;
        END

        IF @state_code <> 'RCD'
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK02' AS result_code,
                   NULL AS task_id, NULL AS destination_bin_code, NULL AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS stock_state_code, NULL AS stock_status_code,
                   NULL AS expires_at, NULL AS zone_code;
            ROLLBACK; RETURN;
        END

        SELECT @source_bin_id = bin_id FROM inventory.inventory_placements
        WHERE inventory_unit_id = @inventory_unit_id;

        IF @source_bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK03' AS result_code,
                   NULL AS task_id, NULL AS destination_bin_code, NULL AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS stock_state_code, NULL AS stock_status_code,
                   NULL AS expires_at, NULL AS zone_code;
            ROLLBACK; RETURN;
        END

        SELECT @source_bin_code = b.bin_code, @zone_code = z.zone_code
        FROM locations.bins b
        LEFT JOIN locations.zones z ON z.zone_id = b.zone_id
        WHERE b.bin_id = @source_bin_id;

        SELECT TOP (1) @task_id = task_id, @dest_bin_id = destination_bin_id, @expires_at = expires_at
        FROM warehouse.warehouse_tasks
        WHERE inventory_unit_id = @inventory_unit_id AND task_state_code IN ('OPN','CLM')
        ORDER BY created_at DESC;

        IF @task_id IS NOT NULL
        BEGIN
            SELECT @dest_bin_code = bin_code FROM locations.bins WHERE bin_id = @dest_bin_id;
            COMMIT;
            SELECT CAST(1 AS BIT) AS success, N'SUCTASK01' AS result_code,
                   @task_id AS task_id, @dest_bin_code AS destination_bin_code,
                   @inventory_unit_id AS inventory_unit_id, @source_bin_code AS source_bin_code,
                   @state_code AS stock_state_code, @stock_status_code AS stock_status_code,
                   @expires_at AS expires_at, @zone_code AS zone_code;
            RETURN;
        END

        EXEC locations.usp_suggest_putaway_bin
            @inventory_unit_id = @inventory_unit_id, @suggested_bin_id = @dest_bin_id OUTPUT;

        IF @dest_bin_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRTASK04' AS result_code,
                   NULL AS task_id, NULL AS destination_bin_code, NULL AS inventory_unit_id,
                   NULL AS source_bin_code, NULL AS stock_state_code, NULL AS stock_status_code,
                   NULL AS expires_at, NULL AS zone_code;
            ROLLBACK; RETURN;
        END

        SELECT @dest_bin_code = bin_code FROM locations.bins WHERE bin_id = @dest_bin_id;

        SELECT @ttl_seconds = TRY_CAST(setting_value AS INT)
        FROM operations.settings WHERE setting_name = 'warehouse.putaway_task_ttl_seconds';

        IF @ttl_seconds IS NULL SET @ttl_seconds = 300;
        SET @expires_at = DATEADD(SECOND, @ttl_seconds, SYSUTCDATETIME());

        INSERT INTO warehouse.warehouse_tasks
            (task_type_code, inventory_unit_id, source_bin_id, destination_bin_id, task_state_code, expires_at, created_by)
        VALUES ('PUTAWAY', @inventory_unit_id, @source_bin_id, @dest_bin_id, 'OPN', @expires_at, @user_id);

        SET @task_id = SCOPE_IDENTITY();

        INSERT INTO locations.bin_reservations (bin_id, reservation_type, reserved_by, expires_at)
        VALUES (@dest_bin_id, 'PUTAWAY', @user_id, @expires_at);

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCTASK01' AS result_code,
               @task_id AS task_id, @dest_bin_code AS destination_bin_code,
               @inventory_unit_id AS inventory_unit_id, @source_bin_code AS source_bin_code,
               @state_code AS stock_state_code, @stock_status_code AS stock_status_code,
               @expires_at AS expires_at, @zone_code AS zone_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRTASK99' AS result_code,
               NULL AS task_id, NULL AS destination_bin_code, NULL AS inventory_unit_id,
               NULL AS source_bin_code, NULL AS stock_state_code, NULL AS stock_status_code,
               NULL AS expires_at, NULL AS zone_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 085_post_warehouse\v_units_awaiting_putaway.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW inventory.v_units_awaiting_putaway
AS
SELECT
    iu.inventory_unit_id,
    iu.external_ref,
    iu.sku_id,
    iu.quantity,
    iu.created_at
FROM inventory.inventory_units iu
WHERE
    iu.stock_state_code = 'RCD'
    AND NOT EXISTS
    (
        SELECT 1
        FROM warehouse.warehouse_tasks wt
        WHERE wt.inventory_unit_id = iu.inventory_unit_id
          AND wt.task_type_code = 'PUTAWAY'
          AND wt.task_state_code IN ('OPN','CLM')
    );
GO


/********************************************************************************************
    OUTBOUND SCHEMA
    Tables, status masters, transitions, error codes.
    Schema: outbound
********************************************************************************************/

/********************************************************************************************
    WIP PATCH — Outbound schema
    Date: 2026-04-17

    1.  Create outbound schema
    2.  Stock state additions: PTW->PKD, PKD->SHP, PKD->PTW
    3.  outbound_order_statuses + transitions
    4.  outbound_line_statuses + transitions
    5.  allocation_statuses
    6.  shipment_statuses + transitions
    7.  outbound_orders
    8.  outbound_lines
    9.  outbound_allocations
    10. shipments
    11. shipment_orders
    12. Indexes
    13. Error codes
********************************************************************************************/


/********************************************************************************************
    1. Schema
********************************************************************************************/
IF NOT EXISTS (SELECT 1 FROM sys.schemas WHERE name = 'outbound')
    EXEC('CREATE SCHEMA outbound');
GO
PRINT 'outbound schema ready.';
GO


/********************************************************************************************
    2. Stock state additions for outbound lifecycle
       PTW → PKD   unit picked from rack
       PKD → SHP   unit shipped
       PKD → PTW   pick reversed — unit returned to storage
********************************************************************************************/
MERGE inventory.stock_state_transitions AS tgt
USING (VALUES
    ('PTW', 'PKD', 0, 'Unit picked from storage'),
    ('PKD', 'SHP', 0, 'Unit shipped'),
    ('PKD', 'PTW', 1, 'Pick reversed — unit returned to storage')
) AS src (from_state_code, to_state_code, requires_authority, notes)
ON  tgt.from_state_code = src.from_state_code
AND tgt.to_state_code   = src.to_state_code
WHEN NOT MATCHED THEN
    INSERT (from_state_code, to_state_code, requires_authority, notes)
    VALUES (src.from_state_code, src.to_state_code, src.requires_authority, src.notes);
GO
PRINT 'Outbound stock state transitions merged.';
GO


/********************************************************************************************
    3. outbound_order_statuses + transitions
********************************************************************************************/
GO


-- -----------------------------------------------------------------------------
-- 085_post_warehouse\v_warehouse_tasks.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW warehouse.v_warehouse_tasks
AS
SELECT
    wt.task_id,
    wt.task_type_code,
    ts.state_desc                                   AS task_state,
    wt.task_state_code,
    ts.is_terminal,

    -- Inventory unit
    iu.inventory_unit_id,
    iu.external_ref                                 AS sscc,
    s.sku_code,
    s.sku_description,
    iu.quantity,
    iu.batch_number,

    -- Bins
    sb.bin_code                                     AS source_bin,
    db.bin_code                                     AS destination_bin,

    -- Assignment
    claimed_usr.username                            AS claimed_by,
    wt.claimed_at,
    wt.expires_at,

    -- Completion
    completed_usr.username                          AS completed_by,
    wt.completed_at,

    -- Audit
    created_usr.username                            AS created_by,
    wt.created_at,
    wt.updated_at

FROM warehouse.warehouse_tasks wt
JOIN warehouse.task_states ts
    ON ts.state_code = wt.task_state_code
JOIN inventory.inventory_units iu
    ON iu.inventory_unit_id = wt.inventory_unit_id
JOIN inventory.skus s
    ON s.sku_id = iu.sku_id
LEFT JOIN locations.bins sb
    ON sb.bin_id = wt.source_bin_id
LEFT JOIN locations.bins db
    ON db.bin_id = wt.destination_bin_id
LEFT JOIN auth.users claimed_usr
    ON claimed_usr.id = wt.claimed_by_user_id
LEFT JOIN auth.users completed_usr
    ON completed_usr.id = wt.completed_by_user_id
LEFT JOIN auth.users created_usr
    ON created_usr.id = wt.created_by;
GO
PRINT 'warehouse.v_warehouse_tasks created.';
GO


