        PRIMARY KEY (from_status_code, to_status_code),

    CONSTRAINT FK_oost_from FOREIGN KEY (from_status_code)
        REFERENCES outbound.outbound_order_statuses(status_code),

    CONSTRAINT FK_oost_to FOREIGN KEY (to_status_code)
        REFERENCES outbound.outbound_order_statuses(status_code)
);
