    ('PICKING',   'PICKED',    0),
    ('PICKING',   'ALLOCATED', 1),  -- partial reverse
    ('PICKING',   'CNL',       1),
    ('PICKED',    'LOADED',    0),
    ('PICKED',    'PICKING',   1),  -- un-pick
