-- -----------------------------------------------------------------------------
-- 090_outbound\usp_cancel_allocation.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE outbound.usp_cancel_allocation
(
    @allocation_id  INT,
    @reason         NVARCHAR(200) = NULL,
    @user_id        INT,
    @session_id     UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    DECLARE
        @alloc_status       VARCHAR(10),
        @is_terminal        BIT,
        @outbound_line_id   INT,
        @allocated_qty      INT,
        @line_status        VARCHAR(10),
        @now                DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        /* ── 1. Lock and read allocation ── */
        SELECT
            @alloc_status     = a.allocation_status,
            @outbound_line_id = a.outbound_line_id,
            @allocated_qty    = a.allocated_qty
        FROM outbound.outbound_allocations a WITH (UPDLOCK, HOLDLOCK)
        WHERE a.allocation_id = @allocation_id;

        IF @alloc_status IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRALLOC04' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 2. Check terminal states ── */
        SELECT @is_terminal = is_terminal
        FROM outbound.allocation_statuses
        WHERE status_code = @alloc_status;

        IF @is_terminal = 1
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRALLOC04' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 3. Cancel the allocation ── */
        UPDATE outbound.outbound_allocations
        SET allocation_status = 'CANCELLED',
            updated_at        = @now,
            updated_by        = @user_id
        WHERE allocation_id = @allocation_id;

        /* ── 3b. Cancel any open PICK tasks for this unit ── */
        DECLARE @inv_unit_id INT;
        SELECT @inv_unit_id = inventory_unit_id
        FROM outbound.outbound_allocations
        WHERE allocation_id = @allocation_id;

        UPDATE warehouse.warehouse_tasks
        SET task_state_code = 'CNL',
            updated_at      = @now,
            updated_by      = @user_id
        WHERE inventory_unit_id = @inv_unit_id
          AND task_type_code    = 'PICK'
          AND task_state_code   = 'OPN';

        /* ── 4. Roll back line allocated_qty and status ── */
        SELECT @line_status = line_status_code
        FROM outbound.outbound_lines
        WHERE outbound_line_id = @outbound_line_id;

        UPDATE outbound.outbound_lines
        SET allocated_qty    = allocated_qty - @allocated_qty,
            -- If all allocations cancelled, line goes back to NEW; otherwise stays ALLOCATED/PICKING
            line_status_code = CASE
                WHEN (allocated_qty - @allocated_qty) <= 0 THEN 'NEW'
                ELSE line_status_code
            END,
            updated_at       = @now,
            updated_by       = @user_id
        WHERE outbound_line_id = @outbound_line_id;

        /* ── 5. Reopen order header if it was ALLOCATED or PICKING ── */
        UPDATE outbound.outbound_orders
        SET order_status_code = 'NEW',
            updated_at        = @now,
            updated_by        = @user_id
        WHERE outbound_order_id = (
            SELECT outbound_order_id FROM outbound.outbound_lines
            WHERE outbound_line_id = @outbound_line_id
        )
          AND order_status_code IN ('ALLOCATED', 'PICKING');

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCALLOC02' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRALLOC99' AS result_code;
    END CATCH
END;
GO

PRINT 'outbound.usp_cancel_allocation created.';
GO

PRINT 'outbound.usp_cancel_allocation created.';
GO


-- -----------------------------------------------------------------------------
-- 090_outbound\usp_cancel_order.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE outbound.usp_cancel_order
(
    @outbound_order_id  INT,
    @user_id            INT,
    @session_id         UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    DECLARE
        @order_status   VARCHAR(10),
        @lines_in_flight INT,
        @now            DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        /* ── 1. Lock and read order ── */
        SELECT @order_status = order_status_code
        FROM outbound.outbound_orders WITH (UPDLOCK, HOLDLOCK)
        WHERE outbound_order_id = @outbound_order_id;

        IF @order_status IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD12' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 2. Refuse terminal statuses ── */
        IF @order_status IN ('CANCELLED', 'DEPARTED')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD14' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 3. Hard-refuse if any line is beyond NEW ──
               Line statuses beyond NEW: ALLOCATED, PICKING, PICKED, LOADED, CNL
               We only allow cancellation when ALL active lines are NEW.        */
        SELECT @lines_in_flight = COUNT(*)
        FROM outbound.outbound_lines
        WHERE outbound_order_id = @outbound_order_id
          AND line_status_code NOT IN ('NEW', 'CNL');

        IF @lines_in_flight > 0
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD13' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 4. Cancel all NEW lines ── */
        UPDATE outbound.outbound_lines
        SET line_status_code = 'CNL',
            updated_at       = @now,
            updated_by       = @user_id
        WHERE outbound_order_id = @outbound_order_id
          AND line_status_code  = 'NEW';

        /* ── 5. Cancel the order header ── */
        UPDATE outbound.outbound_orders
        SET order_status_code = 'CANCELLED',
            updated_at        = @now,
            updated_by        = @user_id
        WHERE outbound_order_id = @outbound_order_id;

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCORD11' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRORD99' AS result_code;
    END CATCH
END;
GO

PRINT 'outbound.usp_cancel_order created.';
GO


-- -----------------------------------------------------------------------------
-- 090_outbound\usp_confirm_load.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE outbound.usp_confirm_load
(
    @outbound_order_id  INT,
    @shipment_id        INT,
    @user_id            INT,
    @session_id         UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    DECLARE
        @order_status    VARCHAR(10),
        @order_shipment  INT,
        @now             DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        /* ── 1. Validate order exists and belongs to this shipment ── */
        SELECT
            @order_status   = order_status_code,
            @order_shipment = shipment_id
        FROM outbound.outbound_orders WITH (UPDLOCK, HOLDLOCK)
        WHERE outbound_order_id = @outbound_order_id;

        IF @order_status IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD01' AS result_code;
            ROLLBACK; RETURN;
        END

        IF @order_shipment <> @shipment_id
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD02' AS result_code;
            ROLLBACK; RETURN;
        END

        IF @order_status NOT IN ('PICKED', 'LOADED')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRORD02' AS result_code;
            ROLLBACK; RETURN;
        END

        /* ── 2. Transition order → LOADED ── */
        UPDATE outbound.outbound_orders
        SET order_status_code = 'LOADED',
            updated_at        = @now,
            updated_by        = @user_id
        WHERE outbound_order_id = @outbound_order_id;

        /* ── 3. Transition every picked unit on this order: PKD → LDD,
               remove its placement (physically leaving the warehouse
               floor the moment it's loaded, same convention usp_ship
               already uses at SHP), and log a LOAD movement. Mirrors
               usp_ship's own ship_cursor almost exactly, just scoped to
               one order instead of a whole shipment, and one step earlier
               in the lifecycle. ── */
        DECLARE
            @unit_id      INT,
            @sku_id       INT,
            @qty          INT,
            @status_code  VARCHAR(2),
            @from_bin_id  INT;

        DECLARE load_cursor CURSOR LOCAL FAST_FORWARD FOR
            SELECT
                iu.inventory_unit_id,
                iu.sku_id,
                iu.quantity,
                iu.stock_status_code,
                ip.bin_id
            FROM outbound.outbound_lines ol
            JOIN outbound.outbound_allocations a
                ON a.outbound_line_id = ol.outbound_line_id
               AND a.allocation_status = 'PICKED'
            JOIN inventory.inventory_units iu WITH (UPDLOCK)
                ON iu.inventory_unit_id = a.inventory_unit_id
               AND iu.stock_state_code  = 'PKD'
            LEFT JOIN inventory.inventory_placements ip
                ON ip.inventory_unit_id = iu.inventory_unit_id
            WHERE ol.outbound_order_id = @outbound_order_id;

        OPEN load_cursor;
        FETCH NEXT FROM load_cursor INTO @unit_id, @sku_id, @qty, @status_code, @from_bin_id;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            UPDATE inventory.inventory_units
            SET stock_state_code = 'LDD',
                updated_at       = @now,
                updated_by       = @user_id
            WHERE inventory_unit_id = @unit_id;

            DELETE FROM inventory.inventory_placements
            WHERE inventory_unit_id = @unit_id;

            INSERT INTO inventory.inventory_movements
            (
                inventory_unit_id, sku_id, moved_qty,
                from_bin_id, to_bin_id,
                from_state_code, to_state_code,
                from_status_code, to_status_code,
                movement_type, reference_type, reference_id,
                moved_at, moved_by_user_id, session_id
            )
            VALUES
            (
                @unit_id, @sku_id, @qty,
                @from_bin_id, NULL,
                'PKD', 'LDD',
                @status_code, @status_code,
                'LOAD', 'OUTBOUND', @outbound_order_id,
                @now, @user_id, @session_id
            );

            FETCH NEXT FROM load_cursor INTO @unit_id, @sku_id, @qty, @status_code, @from_bin_id;
        END

        CLOSE load_cursor;
        DEALLOCATE load_cursor;

        /* ── 4. Transition shipment → LOADING if still OPEN ── */
        UPDATE outbound.shipments
        SET shipment_status = 'LOADING',
            updated_at      = @now,
            updated_by      = @user_id
        WHERE shipment_id     = @shipment_id
          AND shipment_status = 'OPEN';

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCLOAD01' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        IF CURSOR_STATUS('local','load_cursor') >= 0 BEGIN CLOSE load_cursor; DEALLOCATE load_cursor; END
        SELECT CAST(0 AS BIT) AS success, N'ERRTASK99' AS result_code;
    END CATCH
END;
GO
PRINT 'outbound.usp_confirm_load redesigned.';
GO

-- Add SUCLOAD01 message
GO


