-- -----------------------------------------------------------------------------
-- 090_outbound\usp_ship.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE outbound.usp_ship
(
    @shipment_id    INT,
    @vehicle_ref    NVARCHAR(50),
    @user_id        INT,
    @session_id     UNIQUEIDENTIFIER
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    EXEC sys.sp_set_session_context @key = N'user_id',    @value = @user_id;
    EXEC sys.sp_set_session_context @key = N'session_id', @value = @session_id;

    DECLARE
        @shipment_status VARCHAR(10),
        @units_shipped   INT = 0,
        @now             DATETIME2(3) = SYSUTCDATETIME();

    BEGIN TRY
        BEGIN TRAN;

        SELECT @shipment_status = shipment_status
        FROM outbound.shipments WITH (UPDLOCK, HOLDLOCK)
        WHERE shipment_id = @shipment_id;

        IF @shipment_status IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP01' AS result_code,
                   NULL AS shipment_id, 0 AS units_shipped;
            ROLLBACK; RETURN;
        END

        IF @shipment_status NOT IN ('OPEN','LOADING')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP02' AS result_code,
                   @shipment_id AS shipment_id, 0 AS units_shipped;
            ROLLBACK; RETURN;
        END

        /* ── Require vehicle ref at departure ── */
        IF @vehicle_ref IS NULL OR LTRIM(RTRIM(@vehicle_ref)) = ''
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP05' AS result_code,
                   @shipment_id AS shipment_id, 0 AS units_shipped;
            ROLLBACK; RETURN;
        END

        /* ── Stamp vehicle ref onto shipment ── */
        UPDATE outbound.shipments
        SET vehicle_ref = LTRIM(RTRIM(@vehicle_ref)),
            updated_at  = SYSUTCDATETIME(),
            updated_by  = @user_id
        WHERE shipment_id = @shipment_id;

        /* ── Check all orders are PICKED or LOADED ── */
        IF EXISTS (
            SELECT 1 FROM outbound.outbound_orders
            WHERE shipment_id       = @shipment_id
              AND order_status_code NOT IN ('PICKED','LOADED','CNL')
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP04' AS result_code,
                   @shipment_id AS shipment_id, 0 AS units_shipped;
            ROLLBACK; RETURN;
        END

        /* ── Load is mandatory before ship: reject if anything on this
               shipment is still sitting at PICKED (load never confirmed) ── */
        IF EXISTS (
            SELECT 1 FROM outbound.outbound_orders
            WHERE shipment_id       = @shipment_id
              AND order_status_code = 'PICKED'
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP09' AS result_code,
                   @shipment_id AS shipment_id, 0 AS units_shipped;
            ROLLBACK; RETURN;
        END

        /* ── Ship each allocated unit ── */
        DECLARE
            @unit_id           INT,
            @sku_id            INT,
            @qty               INT,
            @status_code       VARCHAR(2),
            @from_state        VARCHAR(3),
            @from_bin_id       INT;

        DECLARE ship_cursor CURSOR LOCAL FAST_FORWARD FOR
            SELECT
                iu.inventory_unit_id,
                iu.sku_id,
                iu.quantity,
                iu.stock_status_code,
                iu.stock_state_code,
                ip.bin_id
            FROM outbound.outbound_orders o
            JOIN outbound.outbound_lines ol
                ON ol.outbound_order_id = o.outbound_order_id
            JOIN outbound.outbound_allocations a
                ON a.outbound_line_id = ol.outbound_line_id
               AND a.allocation_status = 'PICKED'
            JOIN inventory.inventory_units iu WITH (UPDLOCK)
                ON iu.inventory_unit_id = a.inventory_unit_id
            LEFT JOIN inventory.inventory_placements ip
                ON ip.inventory_unit_id = iu.inventory_unit_id
            WHERE o.shipment_id = @shipment_id;

        OPEN ship_cursor;
        FETCH NEXT FROM ship_cursor INTO @unit_id, @sku_id, @qty, @status_code, @from_state, @from_bin_id;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            /* Transition unit → SHP (from whichever state it's actually in -
               LDD if load was confirmed, PKD in the (now blocked-by-default)
               case load was somehow skipped) */
            UPDATE inventory.inventory_units
            SET stock_state_code = 'SHP',
                updated_at       = @now,
                updated_by       = @user_id
            WHERE inventory_unit_id = @unit_id;

            /* Remove placement — unit is no longer in the warehouse.
               No-op if LOAD already removed it. */
            DELETE FROM inventory.inventory_placements
            WHERE inventory_unit_id = @unit_id;

            /* Write SHIP movement */
            INSERT INTO inventory.inventory_movements
            (
                inventory_unit_id, sku_id, moved_qty,
                from_bin_id, to_bin_id,
                from_state_code, to_state_code,
                from_status_code, to_status_code,
                movement_type, reference_type, reference_id,
                moved_at, moved_by_user_id, session_id
            )
            VALUES
            (
                @unit_id, @sku_id, @qty,
                @from_bin_id, NULL,
                @from_state, 'SHP',
                @status_code, @status_code,
                'SHIP', 'SHIPMENT', @shipment_id,
                @now, @user_id, @session_id
            );

            SET @units_shipped += 1;

            FETCH NEXT FROM ship_cursor INTO @unit_id, @sku_id, @qty, @status_code, @from_state, @from_bin_id;
        END

        CLOSE ship_cursor;
        DEALLOCATE ship_cursor;

        /* ── Update all orders on shipment → SHIPPED ── */
        UPDATE outbound.outbound_orders
        SET order_status_code = 'SHIPPED',
            updated_at        = @now,
            updated_by        = @user_id
        WHERE shipment_id       = @shipment_id
          AND order_status_code IN ('PICKED','LOADED');

        /* ── Update all lines on these orders → PICKED (terminal) ── */
        UPDATE ol
        SET ol.line_status_code = 'PICKED',
            ol.updated_at       = @now,
            ol.updated_by       = @user_id
        FROM outbound.outbound_lines ol
        JOIN outbound.outbound_orders o
            ON o.outbound_order_id = ol.outbound_order_id
        WHERE o.shipment_id = @shipment_id
          AND ol.line_status_code <> 'CNL';

        /* ── Close shipment ── */
        UPDATE outbound.shipments
        SET shipment_status  = 'DEPARTED',
            actual_departure = @now,
            updated_at       = @now,
            updated_by       = @user_id
        WHERE shipment_id = @shipment_id;

        COMMIT;

        SELECT CAST(1 AS BIT) AS success, N'SUCSHIP02' AS result_code,
               @shipment_id AS shipment_id, @units_shipped AS units_shipped;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        IF CURSOR_STATUS('local','ship_cursor') >= 0 BEGIN CLOSE ship_cursor; DEALLOCATE ship_cursor; END
        SELECT CAST(0 AS BIT) AS success, N'ERRSHIP01' AS result_code,
               NULL AS shipment_id, 0 AS units_shipped;
    END CATCH
END;

GO
GO


/********************************************************************************************
    LOAD CONFIRMATION SP + SUCLOAD01 MESSAGE
    usp_confirm_load redesigned — order-level confirmation, no SSCC scanning
********************************************************************************************/

/********************************************************************************************
    WIP PATCH — Load confirmation redesign
    Date: 2026-04-18

    usp_confirm_load: redesigned — takes order_id + shipment_id
    Operator confirms an order is loaded onto the vehicle.
    No SSCC scanning — pick already confirmed which units are where.

    Contract: success BIT | result_code NVARCHAR(20)
********************************************************************************************/
GO


-- -----------------------------------------------------------------------------
-- 095_post_outbound\usp_cancel_shipment.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE outbound.usp_cancel_shipment
(
    @shipment_ref    NVARCHAR(50),
    @reason          NVARCHAR(200)    = NULL,
    @user_id         INT              = NULL,
    @session_id      UNIQUEIDENTIFIER = NULL,
    @correlation_id  UNIQUEIDENTIFIER = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    BEGIN TRY
        BEGIN TRAN;

        DECLARE @shipment_id     INT;
        DECLARE @shipment_status VARCHAR(10);

        SELECT
            @shipment_id     = shipment_id,
            @shipment_status = shipment_status
        FROM outbound.shipments WITH (UPDLOCK, HOLDLOCK)
        WHERE shipment_ref = @shipment_ref COLLATE Latin1_General_CS_AS;

        -- Not found
        IF @shipment_id IS NULL
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP06' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Already terminal
        IF @shipment_status IN ('DEPARTED', 'CNL')
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP07' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Has orders with picked/loaded units — cannot cancel
        IF EXISTS (
            SELECT 1
            FROM outbound.shipment_orders so
            JOIN outbound.outbound_orders o ON o.outbound_order_id = so.outbound_order_id
            WHERE so.shipment_id = @shipment_id
              AND o.order_status_code IN ('PICKING', 'PICKED', 'LOADED')
        )
        BEGIN
            SELECT CAST(0 AS BIT) AS success, N'ERRSHIP08' AS result_code;
            ROLLBACK; RETURN;
        END

        -- Remove all order associations
        DELETE FROM outbound.shipment_orders
        WHERE shipment_id = @shipment_id;

        -- Cancel the shipment
        UPDATE outbound.shipments
        SET shipment_status = 'CNL',
            updated_at      = SYSUTCDATETIME(),
            updated_by      = @user_id
        WHERE shipment_id = @shipment_id;

        -- Log
        INSERT INTO audit.trace_logs
            (occurred_at, correlation_id, user_id, session_id, level, action, payload_json)
        VALUES
        (
            SYSUTCDATETIME(),
            @correlation_id,
            @user_id,
            @session_id,
            'INFO',
            'Outbound.CancelShipment',
            (SELECT
                @user_id          AS UserId,
                @session_id       AS SessionId,
                @correlation_id   AS CorrelationId,
                'SUCSHIP04'       AS ResultCode,
                CAST(1 AS BIT)    AS Success,
                @shipment_id      AS ShipmentId,
                @shipment_ref     AS ShipmentRef,
                @reason           AS Reason
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER)
        );

        COMMIT;
        SELECT CAST(1 AS BIT) AS success, N'SUCSHIP04' AS result_code;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        SELECT CAST(0 AS BIT) AS success, N'ERRSHIP99' AS result_code;
    END CATCH
END;
GO


-- -----------------------------------------------------------------------------
-- 095_post_outbound\v_active_inventory.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW inventory.v_active_inventory
AS
SELECT
    iu.inventory_unit_id,
    iu.external_ref                                     AS sscc,
    s.sku_code,
    s.sku_description,
    iu.batch_number,
    iu.best_before_date,
    iu.quantity,
    ss.state_code_desc                                  AS stock_state,
    sst.status_desc                                     AS stock_status,
    b.bin_code,
    z.zone_code,
    st.storage_type_code,
    iu.created_at                                       AS received_at,
    rcv.username                                        AS received_by,
    -- Last physical movement
    lm.movement_type                                    AS last_movement_type,
    lm.moved_at                                         AS last_movement_at,
    lm_usr.username                                     AS last_moved_by,
    -- Allocation state
    ob.order_ref,
    ob.allocation_status,
    ob.allocated_by,
    ob.allocated_at,
    -- Inbound reference
    inb.inbound_ref,
    -- Stock owner (from SKU definition)
    owner_p.display_name                                AS owner_name
FROM inventory.inventory_units iu
JOIN inventory.skus s
    ON s.sku_id = iu.sku_id
JOIN inventory.stock_states ss
    ON ss.state_code = iu.stock_state_code
JOIN inventory.stock_statuses sst
    ON sst.status_code = iu.stock_status_code
JOIN inventory.inventory_placements ip
    ON ip.inventory_unit_id = iu.inventory_unit_id
JOIN locations.bins b
    ON b.bin_id = ip.bin_id
LEFT JOIN locations.zones z
    ON z.zone_id = b.zone_id
LEFT JOIN locations.storage_types st
    ON st.storage_type_id = b.storage_type_id
LEFT JOIN auth.users rcv
    ON rcv.id = iu.created_by
OUTER APPLY
(
    SELECT TOP 1
        m.movement_type,
        m.moved_at,
        m.moved_by_user_id
    FROM inventory.inventory_movements m
    WHERE m.inventory_unit_id = iu.inventory_unit_id
      AND m.is_reversal = 0
    ORDER BY m.moved_at DESC
) lm
LEFT JOIN auth.users lm_usr
    ON lm_usr.id = lm.moved_by_user_id
LEFT JOIN
(
    SELECT r.inventory_unit_id, d.inbound_ref
    FROM inbound.inbound_receipts r
    JOIN inbound.inbound_lines l ON l.inbound_line_id = r.inbound_line_id
    JOIN inbound.inbound_deliveries d ON d.inbound_id = l.inbound_id
    WHERE r.is_reversal = 0
) inb ON inb.inventory_unit_id = iu.inventory_unit_id
LEFT JOIN core.parties owner_p ON owner_p.party_id = s.owner_party_id
LEFT JOIN
(
    SELECT
        a.inventory_unit_id,
        o.order_ref,
        a.allocation_status,
        alloc_usr.username  AS allocated_by,
        a.allocated_at
    FROM outbound.outbound_allocations a
    JOIN outbound.outbound_lines ol ON ol.outbound_line_id = a.outbound_line_id
    JOIN outbound.outbound_orders o ON o.outbound_order_id = ol.outbound_order_id
    LEFT JOIN auth.users alloc_usr ON alloc_usr.id = a.allocated_by
    WHERE a.allocation_status <> 'CANCELLED'
) ob ON ob.inventory_unit_id = iu.inventory_unit_id;
GO


-- -----------------------------------------------------------------------------
-- 095_post_outbound\v_movements.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW inventory.v_movements
AS
SELECT
    m.movement_id,
    m.moved_at,
    u.username                              AS moved_by,
    iu.external_ref                         AS sscc,
    s.sku_code,
    s.sku_description,
    m.moved_qty,
    -- Location transition
    fb.bin_code                             AS from_bin,
    tb.bin_code                             AS to_bin,
    -- State transition
    m.from_state_code,
    m.to_state_code,
    -- Status transition
    m.from_status_code,
    m.to_status_code,
    -- Business context
    m.movement_type,
    m.reference_type,
    m.reference_id,
    -- Resolve reference display string
    CASE m.reference_type
        WHEN 'INBOUND'  THEN (SELECT inbound_ref  FROM inbound.inbound_deliveries  WHERE inbound_id        = m.reference_id)
        WHEN 'OUTBOUND' THEN (SELECT order_ref    FROM outbound.outbound_orders     WHERE outbound_order_id = m.reference_id)
        WHEN 'SHIPMENT' THEN (SELECT shipment_ref FROM outbound.shipments            WHERE shipment_id       = m.reference_id)
        WHEN 'RECEIPT'  THEN (
            SELECT d.inbound_ref
            FROM inbound.inbound_receipts r
            JOIN inbound.inbound_lines l    ON l.inbound_line_id = r.inbound_line_id
            JOIN inbound.inbound_deliveries d ON d.inbound_id   = l.inbound_id
            WHERE r.receipt_id = m.reference_id
        )
        WHEN 'TASK'     THEN (
            SELECT CASE t.task_type_code
                WHEN 'PUTAWAY' THEN 'PUT-'  + RIGHT('000000' + CAST(t.task_id AS VARCHAR(6)), 6)
                WHEN 'PICK'    THEN 'PICK-' + RIGHT('000000' + CAST(t.task_id AS VARCHAR(6)), 6)
                WHEN 'MOVE'    THEN 'MOVE-' + RIGHT('000000' + CAST(t.task_id AS VARCHAR(6)), 6)
                ELSE CAST(t.task_id AS NVARCHAR(20))
            END
            FROM warehouse.warehouse_tasks t
            WHERE t.task_id = m.reference_id
        )
        ELSE NULL
    END                                     AS reference_ref,
    -- Reversal flag
    m.is_reversal,
    m.reversed_movement_id
FROM inventory.inventory_movements m
JOIN inventory.inventory_units iu   ON iu.inventory_unit_id = m.inventory_unit_id
JOIN inventory.skus s               ON s.sku_id             = m.sku_id
JOIN auth.users u                   ON u.id                 = m.moved_by_user_id
LEFT JOIN locations.bins fb         ON fb.bin_id            = m.from_bin_id
LEFT JOIN locations.bins tb         ON tb.bin_id            = m.to_bin_id;
GO
PRINT 'inventory.v_movements created.';
GO


-- -----------------------------------------------------------------------------
-- 095_post_outbound\v_shipment_manifest.sql
-- -----------------------------------------------------------------------------

SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER VIEW outbound.v_shipment_manifest
AS
SELECT
    -- Shipment header
    s.shipment_id,
    s.shipment_ref,
    s.shipment_status,
    s.vehicle_ref,
    s.actual_departure,
    -- Haulier
    h.display_name                              AS haulier_name,
    h.party_code                                AS haulier_code,
    -- Customer (from first order on shipment — all orders on same shipment = same customer)
    cust.display_name                           AS customer_name,
    cust.party_code                             AS customer_code,
    -- Delivery address (from first order)
    ca.line_1                                AS delivery_line_1,
    ca.city                                     AS delivery_city,
    ca.postal_code                              AS delivery_postal_code,
    ca.country_code                             AS delivery_country,
    -- Pallet detail
    m.movement_id,
    iu.external_ref                             AS sscc,
    sk.sku_code,
    sk.sku_description,
    iu.batch_number,
    iu.best_before_date,
    m.moved_qty                                 AS quantity,
    sk.uom_code,
    sk.weight_per_unit,
    CAST(sk.weight_per_unit * m.moved_qty AS DECIMAL(10,3)) AS total_weight_kg,
    -- Order reference for this unit
    ol_alloc.order_ref,
    -- Bin it was picked from
    fb.bin_code                                 AS picked_from_bin
FROM outbound.shipments s
LEFT JOIN core.parties h ON h.party_id = s.haulier_party_id
-- Get customer and delivery address from first order on shipment
OUTER APPLY (
    SELECT TOP 1
        o.customer_party_id,
        o.delivery_address_id
    FROM outbound.shipment_orders so2
    JOIN outbound.outbound_orders o ON o.outbound_order_id = so2.outbound_order_id
    WHERE so2.shipment_id = s.shipment_id
) first_order
LEFT JOIN core.parties cust ON cust.party_id = first_order.customer_party_id
LEFT JOIN core.party_addresses ca ON ca.address_id = first_order.delivery_address_id
-- Physical units shipped
JOIN inventory.inventory_movements m
    ON  m.reference_type = 'SHIPMENT'
    AND m.reference_id   = s.shipment_id
    AND m.movement_type  = 'SHIP'
    AND m.is_reversal    = 0
JOIN inventory.inventory_units iu ON iu.inventory_unit_id = m.inventory_unit_id
JOIN inventory.skus sk            ON sk.sku_id             = m.sku_id
LEFT JOIN locations.bins fb       ON fb.bin_id             = m.from_bin_id
-- Resolve which order this unit was on (via allocation)
OUTER APPLY (
    SELECT TOP 1 o.order_ref
    FROM outbound.outbound_allocations a
    JOIN outbound.outbound_lines ol ON ol.outbound_line_id = a.outbound_line_id
    JOIN outbound.outbound_orders o ON o.outbound_order_id = ol.outbound_order_id
    WHERE a.inventory_unit_id = iu.inventory_unit_id
      AND a.allocation_status  = 'PICKED'
) ol_alloc;
GO
PRINT 'outbound.v_shipment_manifest created.';
GO


